const applyCursor = (file) => {
  let styleEl = document.getElementById('custom-cursor-style')
  if (!styleEl) {
    styleEl = document.createElement('style')
    styleEl.id = 'custom-cursor-style'
    document.head.appendChild(styleEl)
  }
  if (file) {
    const url = `/customcursor/${file.replace(/ /g, '%20')}`
    styleEl.textContent = `* { cursor: url('${url}'), auto !important; }`
  } else {
    styleEl.textContent = ''
  }
}

const applyVttCursor = (src) => {
  let styleEl = document.getElementById('vtt-cursor-override-style')
  if (!styleEl) {
    styleEl = document.createElement('style')
    styleEl.id = 'vtt-cursor-override-style'
  }
  // Re-append sempre ao final do <head> para vencer qualquer outro cursor !important
  document.head.appendChild(styleEl)
  if (!src) {
    styleEl.textContent = ''
    return
  }
  const img = new Image()
  img.onload = () => {
    const size = 40
    const canvas = document.createElement('canvas')
    canvas.width = size
    canvas.height = size
    canvas.getContext('2d').drawImage(img, 0, 0, size, size)
    const dataUrl = canvas.toDataURL('image/png')
    styleEl.textContent = `* { cursor: url('${dataUrl}') ${size / 2} ${size / 2}, crosshair !important; }`
  }
  img.onerror = () => { styleEl.textContent = '' }
  img.src = src
}

// Firebase não permite ".", "#", "$", "/", "[", ou "]" em chaves
const sanitizeFirebaseKey = (key) => {
  if (!key) return key
  return String(key).replace(/[.#$/\[\]]/g, '_')
}

// Parser matemático seguro — substitui eval() para evitar bloqueio de CSP
// Suporta +, -, *, /, parênteses e números decimais
const safeMathEval = (expr) => {
  let pos = 0
  const str = String(expr).replace(/\s/g, '')
  const parseExpr = () => {
    let result = parseTerm()
    while (pos < str.length && (str[pos] === '+' || str[pos] === '-')) {
      const op = str[pos++]
      const term = parseTerm()
      result = op === '+' ? result + term : result - term
    }
    return result
  }
  const parseTerm = () => {
    let result = parseFactor()
    while (pos < str.length && (str[pos] === '*' || str[pos] === '/')) {
      const op = str[pos++]
      const factor = parseFactor()
      result = op === '*' ? result * factor : result / factor
    }
    return result
  }
  const parseFactor = () => {
    if (str[pos] === '(') { pos++; const r = parseExpr(); pos++; return r }
    if (str[pos] === '-') { pos++; return -parseFactor() }
    if (str[pos] === '+') { pos++; return parseFactor() }
    let numStr = ''
    while (pos < str.length && /[\d.]/.test(str[pos])) numStr += str[pos++]
    return parseFloat(numStr) || 0
  }
  return parseExpr()
}

