  'Sombrio':   { strong: ['Psíquico', 'Fantasma'], weak: ['Lutador', 'Sombrio', 'Fada'], immune: [] },
  'Psíquico':  { strong: ['Lutador', 'Venenoso'], weak: ['Psíquico', 'Metal'], immune: ['Sombrio'] },
