  const ataqueEspecialEfetivo = attributes.ataqueEspecial + (rotinaEstudosValues.ataqueEspecial || 0)
  const defesaEspecialEfetiva = attributes.defesaEspecial + (rotinaEstudosValues.defesaEspecial || 0)

