        setExoticDataForm({
          dexNumber: '',
          altura: '',
          peso: '',
          genero: '',
          tipos: [],
          habitats: [''],
          catchRate: '',
          baseExp: '',
          evolucao: '',
          evolucaoNivel: '',
          evolucaoItem: '',
          statusBasais: {
            saude: '',
            ataque: '',
            defesa: '',
            ataqueEspecial: '',
            defesaEspecial: '',
            velocidade: ''
          }
        })
