  const fetchSafariPokemonData = async (speciesName) => {
    try {
      const id = speciesName.toLowerCase().replace(/\s+/g, '-').replace(/[^a-z0-9-]/g, '')
      const response = await fetch(`https://pokeapi.co/api/v2/pokemon/${id}`)
      if (!response.ok) return { imageUrl: null, types: [] }
      const data = await response.json()
      const imageUrl = data.sprites.other['official-artwork'].front_default ||
        data.sprites.other['home'].front_default ||
        data.sprites.front_default
      const types = data.types.map(t => t.type.name)
      return { imageUrl, types }
    } catch (error) {
      return { imageUrl: null, types: [] }
    }
  }

  // Gerar Pokémon NPC completo para Safari (com atributos, golpes, habilidades)
  const generateSafariNpcPokemon = (speciesName, level, isSkittish, imageUrl, types) => {
    const speciesData = pokedexData.find(p => p.nome.toLowerCase() === speciesName.toLowerCase())
    const baseStats = speciesData?.statusBasais || { saude: 5, ataque: 5, defesa: 5, ataqueEspecial: 5, defesaEspecial: 5, velocidade: 5 }

    // Sortear natureza
    const nature = natures[Math.floor(Math.random() * natures.length)]

    // Distribuir pontos de nível aleatoriamente
    const statKeys = ['saude', 'ataque', 'defesa', 'ataqueEspecial', 'defesaEspecial', 'velocidade']
    const levelPts = { saude: 0, ataque: 0, defesa: 0, ataqueEspecial: 0, defesaEspecial: 0, velocidade: 0 }
    for (let i = 0; i < level; i++) {
      levelPts[statKeys[Math.floor(Math.random() * statKeys.length)]]++
    }

    // Mapa de natureza para chave de atributo
    const natureMap = { 'Saúde': 'saude', 'Ataque': 'ataque', 'Defesa': 'defesa', 'Ataque Especial': 'ataqueEspecial', 'Defesa Especial': 'defesaEspecial', 'Velocidade': 'velocidade' }
    const upKey = natureMap[nature.up]
    const downKey = natureMap[nature.down]

    // Calcular atributos totais
    const baseAttributes = { ...baseStats }
    const attributes = {}
    for (const key of statKeys) {
      let total = baseStats[key] + levelPts[key]
      if (key === upKey) total += key === 'saude' ? 1 : 2
      if (key === downKey) total -= key === 'saude' ? 1 : 2
      attributes[key] = total
    }

    // Gerar golpes
    const golpesAprendidos = generatePokemonMoves(speciesName, level, false, null)

    // Gênero
    let gender = null
    if (speciesData?.genero) {
      const gParts = speciesData.genero.split('_')
      const mP = parseFloat(gParts[0])
      const fP = parseFloat(gParts[1])
      if (mP === 0 && fP === 0) gender = null
      else if (mP === 100) gender = 'Macho'
      else if (fP === 100) gender = 'Fêmea'
      else gender = Math.random() * 100 < mP ? 'Macho' : 'Fêmea'
    }

    const pokemon = {
      id: `safari-${Date.now()}-${Math.random()}`,
      species: speciesName,
      name: speciesName,
      level,
      isSkittish,
      imageUrl,
      types: types || [],
      nature,
      baseAttributes,
      attributes,
      levelPoints: levelPts,
      golpesAprendidos,
      gender,
      dexNumber: speciesData?.dexNumber || 0,
      catchRate: speciesData?.catchRate || 0,
      experience: speciesData?.baseExp || 0,
      weight: speciesData?.peso || 0,
      height: speciesData?.altura || 0,
      shiny: false,
      currentHP: (3 * attributes.saude) + level,
      chanceFuga: isSkittish ? 70 : 90,
      chanceCaptura: 0,
      conditions: {},
      outrasCapacidades: getOutrasCapacidadesArray(speciesName)
    }

    return assignAbilitiesToPokemon(pokemon)
  }

  // Encontrar tile especial no grid
  const findSpecialTile = (grid, type) => {
    for (let r = 0; r < grid.length; r++) {
      for (let c = 0; c < grid[r].length; c++) {
        if (grid[r][c].specialTile === type) return { row: r, col: c }
      }
    }
    return null
  }

  // Encontrar tile não-lava mais distante do tile de corda (distância Manhattan)
  const getFarthestTileFromRope = (grid, ropePos) => {
    let farthest = null
    let maxDist = -1
    for (let r = 0; r < grid.length; r++) {
      for (let c = 0; c < grid[r].length; c++) {
        const cell = grid[r][c]
        if (cell.specialTile === 'lava' || cell.specialTile === 'rope') continue
        const dist = Math.abs(r - ropePos.row) + Math.abs(c - ropePos.col)
        if (dist > maxDist) {
          maxDist = dist
          farthest = { row: r, col: c }
        }
      }
    }
    return farthest
  }

  // Gerar grid 8x8 do Safari
  const generateSafariGrid = (areaName) => {
    const isFrozenCave = FROZEN_CAVE_AREAS.includes(areaName)
    const isCave = CAVE_AREAS.includes(areaName)

    // Geração de grid para cavernas congeladas
    if (isFrozenCave) {
      const GRID_SIZE = 8
      const centerCells = [{ row: 3, col: 3 }, { row: 3, col: 4 }, { row: 4, col: 3 }, { row: 4, col: 4 }]
      const corners = [{ row: 0, col: 0 }, { row: 0, col: 7 }, { row: 7, col: 0 }, { row: 7, col: 7 }]
      const centerCell = centerCells[Math.floor(Math.random() * centerCells.length)]
      const cornerCell = corners[Math.floor(Math.random() * corners.length)]

      const hasHoleNeve = areaName === 'Caverna Congelada 1' || areaName === 'Caverna Congelada 2'
      const hasRopeNeve = areaName === 'Caverna Congelada 2' || areaName === 'Caverna Congelada 3'

      const terrainWeights =
        areaName === 'Caverna Congelada 1' ? { TerraNeivada: 45, Neve: 45, Pedra: 10 } :
        areaName === 'Caverna Congelada 2' ? { Neve: 60, Gelo: 30, Pedra: 10 } :
        { Neve: 40, Gelo: 40, Pedra: 20 }

      const getRandomFrozenTerrain = () => {
        const total = Object.values(terrainWeights).reduce((a, b) => a + b, 0)
        let rand = Math.random() * total
        for (const [terrain, weight] of Object.entries(terrainWeights)) {
          rand -= weight
          if (rand <= 0) return terrain
        }
        return 'Neve'
      }

      const pedraImages = ['/gelosafari/pedra1gelosafari.png', '/gelosafari/pedra2gelosafari.png', '/gelosafari/pedra3gelosafari.png']
      const getRandomPedraImage = () => pedraImages[Math.floor(Math.random() * pedraImages.length)]

      const grid = []
      for (let row = 0; row < GRID_SIZE; row++) {
        const gridRow = []
        for (let col = 0; col < GRID_SIZE; col++) {
          let cell = { terrain: 'Neve', pokemon: null, quantity: 0, isSkittish: false, level: 0, levelRange: '-', revealed: false, specialTile: null, pedraImage: null }

          if (hasHoleNeve && row === centerCell.row && col === centerCell.col) {
            cell.specialTile = 'holeNeve'
          } else if (hasRopeNeve && row === cornerCell.row && col === cornerCell.col) {
            cell.specialTile = 'ropeNeve'
          } else {
            const terrain = getRandomFrozenTerrain()
            cell.terrain = terrain
            if (terrain === 'Pedra') {
              cell.pedraImage = getRandomPedraImage()
            } else if (terrain !== 'Gelo') {
              // Gelo: 0% encontros — sem pokémon
              const encounter = rollSafariEncounter(areaName, terrain)
              if (encounter && encounter.pokemon) {
                const isSolo = SAFARI_SOLO_SPECIES.includes(encounter.pokemon)
                cell.pokemon = encounter.pokemon
                cell.quantity = isSolo ? 1 : Math.floor(Math.random() * 6) + 1
                cell.isSkittish = encounter.isSkittish
                cell.level = parseSafariLevel(encounter.level)
                cell.levelRange = encounter.level
              }
            }
          }
          gridRow.push(cell)
        }
        grid.push(gridRow)
      }
      return grid
    }

    if (!isCave) {
      const grid = []
      for (let row = 0; row < 8; row++) {
        const gridRow = []
        for (let col = 0; col < 8; col++) {
          const terrain = getRandomSafariTerrain(areaName)
          const encounter = rollSafariEncounter(areaName, terrain)
          let cell = { terrain, pokemon: null, quantity: 0, isSkittish: false, level: 0, levelRange: '-', revealed: false, specialTile: null }
          if (encounter && encounter.pokemon) {
            const isSolo = SAFARI_SOLO_SPECIES.includes(encounter.pokemon)
            cell.pokemon = encounter.pokemon
            cell.quantity = isSolo ? 1 : Math.floor(Math.random() * 6) + 1
            cell.isSkittish = encounter.isSkittish
            cell.level = parseSafariLevel(encounter.level)
            cell.levelRange = encounter.level
          }
          gridRow.push(cell)
        }
        grid.push(gridRow)
      }
      return grid
    }

    // Geração de grid para cavernas
    const GRID_SIZE = 8
    const centerCells = [{ row: 3, col: 3 }, { row: 3, col: 4 }, { row: 4, col: 3 }, { row: 4, col: 4 }]
    const corners = [{ row: 0, col: 0 }, { row: 0, col: 7 }, { row: 7, col: 0 }, { row: 7, col: 7 }]

    const centerCell = centerCells[Math.floor(Math.random() * centerCells.length)]
    const cornerCell = corners[Math.floor(Math.random() * corners.length)]

    const hasHole = areaName === 'Caverna 1' || areaName === 'Caverna 2'
    const hasRope = areaName === 'Caverna 2' || areaName === 'Caverna 3'
    const isLavaCave = areaName === 'Caverna 3'

    const grid = []
    for (let row = 0; row < GRID_SIZE; row++) {
      const gridRow = []
      for (let col = 0; col < GRID_SIZE; col++) {
        let cell = { terrain: 'Cave', pokemon: null, quantity: 0, isSkittish: false, level: 0, levelRange: '-', revealed: false, specialTile: null }

        if (hasHole && row === centerCell.row && col === centerCell.col) {
          cell.specialTile = 'hole'
        } else if (hasRope && row === cornerCell.row && col === cornerCell.col) {
          cell.specialTile = 'rope'
        } else if (isLavaCave && Math.random() < 0.6) {
          cell.specialTile = 'lava'
        } else {
          // Célula normal: rolar encontro
          const encounter = rollSafariEncounter(areaName, 'Cave')
          if (encounter && encounter.pokemon) {
            const isSolo = SAFARI_SOLO_SPECIES.includes(encounter.pokemon)
            cell.pokemon = encounter.pokemon
            cell.quantity = isSolo ? 1 : Math.floor(Math.random() * 6) + 1
            cell.isSkittish = encounter.isSkittish
            cell.level = parseSafariLevel(encounter.level)
            cell.levelRange = encounter.level
          }
        }
        gridRow.push(cell)
      }
      grid.push(gridRow)
    }
    return grid
  }

  // --- Ações Mestre Safari ---

  const handleToggleSafariRunPermission = (runNumber, username) => {
    const runKey = `run-${runNumber}`
    const currentPerms = safariRunPermissions[runKey] || {}
    const isCurrentlyChecked = !!currentPerms[username]

    // Se está marcando (tornando true), desmarcar esse treinador de todas as outras runs
    let newRunPermissions = { ...safariRunPermissions }

    if (!isCurrentlyChecked) {
      // Desmarcar o treinador de todas as runs
      for (let i = 1; i <= 5; i++) {
        const otherRunKey = `run-${i}`
        if (newRunPermissions[otherRunKey]) {
          newRunPermissions[otherRunKey] = { ...newRunPermissions[otherRunKey], [username]: false }
        }
      }
    }

    // Atualizar a run atual
    const newPerms = { ...newRunPermissions[runKey] || {}, [username]: !isCurrentlyChecked }
    newRunPermissions = { ...newRunPermissions, [runKey]: newPerms }

    setSafariRunPermissions(newRunPermissions)
    saveSafariToFirebase({ runPermissions: newRunPermissions })
  }

  const handleResetSafari = () => {
    setSafariRunGrids({})
    setSafariRunAreas({})
    setSafariTimers({})
    setSafariRunPermissions({})
    setSafariRunEncounters({})
    setSafariRunPaidUsers({})
    setSafariRunLastClicked({})
    setSafariSaltoValues({})
    setSafariRunStartAreas({})
    setSafariStaffActiveRun(null)
    setSafariActiveRun(null) // Limpar run ativa do jogador
    setSafariGridData(null) // Limpar grid data do jogador
    safariPaidRunsRef.current = new Set()
    setSafariRunLastClicked({})
    saveSafariToFirebase({ runAreas: {}, runPermissions: {}, runEncounters: {}, runPaidUsers: {}, saltoValues: {}, runPositions: {}, runStartAreas: {} })
    saveToFirebase('safariGrids', null)
    saveToFirebase('safariTimers', null)
    const timestamp = new Date().toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' })
    addChatMessage({ username: 'Sistema', text: 'O Safari foi resetado pelo Mestre!', timestamp, isDiceRoll: false })
  }

  const handleEquipeLimpeza = () => {
    setSafariRunEncounters({})
    saveSafariToFirebase({ runEncounters: {} })
  }

  // Mestre define o valor de Salto de um treinador (só Caverna 3)
  const handleSetSalto = (runNumber, value) => {
    const runKey = `run-${runNumber}`
    const newSaltoValues = { ...safariSaltoValues, [runKey]: value }
    setSafariSaltoValues(newSaltoValues)
    saveSafariToFirebase({ saltoValues: newSaltoValues })
  }

  const handleSetRunStartArea = (runNumber, area) => {
    const runKey = `run-${runNumber}`
    const newRunStartAreas = { ...safariRunStartAreas, [runKey]: area }
    setSafariRunStartAreas(newRunStartAreas)
    saveSafariToFirebase({ runStartAreas: newRunStartAreas })
  }

  const handleSafariChanceFugaRoll = (runNumber, pokemonId) => {
    const runKey = `run-${runNumber}`
    const encounters = safariRunEncounters[runKey] || []
    const pokemon = encounters.find(p => p.id === pokemonId)
    if (!pokemon) return

    const roll = Math.floor(Math.random() * 100) + 1
    const timestamp = new Date().toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' })

    if (roll >= pokemon.chanceFuga) {
      const newEncounters = encounters.filter(p => p.id !== pokemonId)
      const newRunEncounters = { ...safariRunEncounters, [runKey]: newEncounters }
      setSafariRunEncounters(newRunEncounters)
      saveSafariToFirebase({ runEncounters: newRunEncounters })
      addChatMessage({ username: 'Sistema', text: `🏃 ${pokemon.species} fugiu!`, timestamp, isDiceRoll: true, diceResult: roll, diceDetails: `1d100 = ${roll} vs Chance de Fuga ${pokemon.chanceFuga}% → Pokémon fugiu!` })
    } else {
      addChatMessage({ username: 'Sistema', text: `${pokemon.species} permanece!`, timestamp, isDiceRoll: true, diceResult: roll, diceDetails: `1d100 = ${roll} vs Chance de Fuga ${pokemon.chanceFuga}% → O pokémon Permanece` })
    }
  }

  const handleToggleSafariCondition = (runNumber, pokemonId, condition) => {
    const runKey = `run-${runNumber}`
    const encounters = safariRunEncounters[runKey] || []
    const newEncounters = encounters.map(p => {
      if (p.id !== pokemonId) return p
      const conds = p.conditions || {}
      return { ...p, conditions: { ...conds, [condition]: !conds[condition] } }
    })
    const newRunEncounters = { ...safariRunEncounters, [runKey]: newEncounters }
    setSafariRunEncounters(newRunEncounters)
    saveSafariToFirebase({ runEncounters: newRunEncounters })
  }

  // Função para remover pokémon Safari manualmente
  const handleRemoveSafariPokemon = (runNumber, pokemonId) => {
    const runKey = `run-${runNumber}`
    const encounters = safariRunEncounters[runKey] || []
    const newEncounters = encounters.filter(p => p.id !== pokemonId)
    const newRunEncounters = { ...safariRunEncounters, [runKey]: newEncounters }
    setSafariRunEncounters(newRunEncounters)
    saveSafariToFirebase({ runEncounters: newRunEncounters })
  }

  // Função para calcular o Valor de Captura do Safari considerando condições
  const calculateSafariCaptureValue = (pokemon) => {
    let total = 0

    // Catch Rate base + Chance Captura adicional
    total += (pokemon.catchRate || 0)
    total += (pokemon.chanceCaptura || 0)

    // Bônus de condições
    const conditions = pokemon.conditions || {}
    if (conditions.confusão) total += 5
    if (conditions.crítico) total += 10
    if (conditions.paralisia) total += 7
    if (conditions.sono) total += 10
    if (conditions.atordoamento) total += 10
    if (conditions.congelamento) total += 15
    if (conditions.paixão) total += 3
    if (conditions.queimadura) total += 5
    if (conditions.veneno) total += 7

    return total
  }

  const toggleSafariNpcCard = (pokemonId) => {
    setExpandedSafariNpcCards(prev =>
      prev.includes(pokemonId) ? prev.filter(id => id !== pokemonId) : [...prev, pokemonId]
    )
  }

  const applySafariNpcDamage = (isDamage) => {
    if (!selectedSafariNpcPokemon || !safariNpcDamageAmount || !safariNpcDamageRunNumber) return
    const amount = parseInt(safariNpcDamageAmount)
    if (isNaN(amount) || amount <= 0) return
    const runKey = `run-${safariNpcDamageRunNumber}`
    const encounters = safariRunEncounters[runKey] || []
    const newEncounters = encounters.map(p => {
      if (p.id !== selectedSafariNpcPokemon.id) return p
      const maxHP = (3 * p.attributes.saude) + p.level
      const currentHP = p.currentHP !== undefined ? p.currentHP : maxHP
      const newHP = isDamage ? Math.max(0, currentHP - amount) : Math.min(maxHP, currentHP + amount)
      return { ...p, currentHP: newHP }
    })
    const newRunEncounters = { ...safariRunEncounters, [runKey]: newEncounters }
    setSafariRunEncounters(newRunEncounters)
    saveSafariToFirebase({ runEncounters: newRunEncounters })
    setShowSafariNpcDamageModal(false)
    setSafariNpcDamageAmount('')
    setSelectedSafariNpcPokemon(null)
    setSafariNpcDamageRunNumber(null)
  }

  // --- Ações Treinador Safari ---

  const handleStartSafariRun = async (runNumber) => {
    const runKey = `run-${runNumber}`

    // Se o run já tem grid, apenas trocar para ele
    if (safariRunGrids[runKey]) {
      setSafariActiveRun(runNumber)
      setSafariGridData(safariRunGrids[runKey])
      setSafariCurrentArea(safariRunAreas[runKey] || 'Área Central')
      setSafariGridClickCount(0)
      setSafariSelectedPokemon(new Set())
      return
    }

    // Primeiro acesso: verificar permissão
    const permissions = safariRunPermissions[runKey] || {}
    if (!permissions[currentUser.username]) {
      alert('Você não tem permissão para iniciar esta run!')
      return
    }

    // Identificar TODOS os treinadores com permissão nesta run
    const trainersInRun = Object.keys(permissions).filter(username => permissions[username])

    // Verificar se TODOS os treinadores têm pokemoedas suficientes
    const trainersData = {}
    for (const trainerUsername of trainersInRun) {
      if (trainerUsername === currentUser.username) {
        if (pokemonedas < SAFARI_ENTRY_COST) {
          alert(`Você não tem ₽${SAFARI_ENTRY_COST} para entrar no Safari!`)
          return
        }
        trainersData[trainerUsername] = { pokemonedas }
      } else {
        // Carregar dados do outro treinador
        const data = useFirebase
          ? await loadTrainerData(trainerUsername)
          : JSON.parse(localStorage.getItem(`trainer_${trainerUsername}`) || 'null')

        if (!data || (data.pokemonedas || 0) < SAFARI_ENTRY_COST) {
          alert(`O treinador ${trainerUsername} não tem ₽${SAFARI_ENTRY_COST} suficientes para entrar no Safari!`)
          return
        }
        trainersData[trainerUsername] = data
      }
    }

    // Cobrar de TODOS os treinadores
    for (const trainerUsername of trainersInRun) {
      if (trainerUsername === currentUser.username) {
        // Cobrar do treinador atual
        setPokemonedas(prev => prev - SAFARI_ENTRY_COST)
      } else {
        // Cobrar do outro treinador
        const trainerData = trainersData[trainerUsername]
        const updatedData = {
          ...trainerData,
          pokemonedas: (trainerData.pokemonedas || 0) - SAFARI_ENTRY_COST
        }
        if (useFirebase) {
          await saveTrainerData(trainerUsername, updatedData)
        } else {
          localStorage.setItem(`trainer_${trainerUsername}`, JSON.stringify(updatedData))
        }
      }
    }

    const startArea = safariRunStartAreas[runKey] || 'Área Central'
    safariPaidRunsRef.current.add(runKey)
    setSafariActiveRun(runNumber)
    setSafariCurrentArea(startArea)
    setSafariGridClickCount(0)
    setSafariSelectedPokemon(new Set())

    // Resetar último clicado ao iniciar nova run
    setSafariRunLastClicked(prev => ({ ...prev, [runKey]: null }))

    const grid = generateSafariGrid(startArea)
    setSafariGridData(grid)

    syncGridToRun(grid, runNumber)
    updateSafariTimer(runNumber, 600)
    const newRunAreas = { ...safariRunAreas, [runKey]: startArea }
    setSafariRunAreas(newRunAreas)
    // Marcar todos os treinadores como pagos
    const newRunPaidUsers = { ...safariRunPaidUsers, [runKey]: trainersInRun }
    setSafariRunPaidUsers(newRunPaidUsers)
    saveSafariToFirebase({ runAreas: newRunAreas, runPaidUsers: newRunPaidUsers })

    const timestamp = new Date().toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' })
    const trainersList = trainersInRun.join(', ')
    addChatMessage({ username: 'Sistema', text: `${trainersList} entraram no Safari Run ${runNumber}! (-₽${SAFARI_ENTRY_COST} cada)`, timestamp, isDiceRoll: false })
  }

  const handleSafariNavigate = (targetArea) => {
    if (!safariActiveRun) return
    const runKey = `run-${safariActiveRun}`

    // Verificar timer
    const currentTimer = safariTimers[runKey] !== undefined ? safariTimers[runKey] : 600
    if (currentTimer <= 0) {
      alert('⏰ Tempo esgotado! Você não pode mais se movimentar no Safari.')
      return
    }

    // Verificar permissão
    const permissions = safariRunPermissions[runKey] || {}
    if (!permissions[currentUser?.username]) {
      alert('Você não tem permissão para navegar nesta run!')
      return
    }

    setSafariCurrentArea(targetArea)
    const grid = generateSafariGrid(targetArea)
    setSafariGridData(grid)
    setSafariGridClickCount(0)

    // Resetar último clicado ao mudar de área
    const resetPositions = Object.fromEntries(Object.entries(safariRunLastClicked).filter(([k]) => k !== runKey))
    setSafariRunLastClicked(resetPositions)

    syncGridToRun(grid, safariActiveRun)
    if (currentTimer > 0) updateSafariTimer(safariActiveRun, currentTimer - 60)

    const newRunAreas = { ...safariRunAreas, [runKey]: targetArea }
    setSafariRunAreas(newRunAreas)
    saveSafariToFirebase({ runAreas: newRunAreas, runPositions: resetPositions })

    setShowAreaNavigationModal(false)
    setSafariSelectedPokemon(new Set())

    const timestamp = new Date().toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' })
    addChatMessage({ username: 'Sistema', text: `${currentUser.username} (Run ${safariActiveRun}) avançou para ${targetArea}!`, timestamp, isDiceRoll: false })
  }

  // Funções helper para validação de cliques no Safari
  const isEdgeCell = (row, col, gridSize = 8) => {
    return row === 0 || row === gridSize - 1 || col === 0 || col === gridSize - 1
  }

  const getAdjacentCells = (row, col, gridSize = 8) => {
    const adjacent = []
    // Ortogonais
    if (row > 0) adjacent.push({ row: row - 1, col }) // cima
    if (row < gridSize - 1) adjacent.push({ row: row + 1, col }) // baixo
    if (col > 0) adjacent.push({ row, col: col - 1 }) // esquerda
    if (col < gridSize - 1) adjacent.push({ row, col: col + 1 }) // direita
    // Diagonais
    if (row > 0 && col > 0) adjacent.push({ row: row - 1, col: col - 1 }) // cima-esquerda
    if (row > 0 && col < gridSize - 1) adjacent.push({ row: row - 1, col: col + 1 }) // cima-direita
    if (row < gridSize - 1 && col > 0) adjacent.push({ row: row + 1, col: col - 1 }) // baixo-esquerda
    if (row < gridSize - 1 && col < gridSize - 1) adjacent.push({ row: row + 1, col: col + 1 }) // baixo-direita
    return adjacent
  }

  const isAdjacentToCell = (row, col, targetRow, targetCol) => {
    const rowDiff = Math.abs(row - targetRow)
    const colDiff = Math.abs(col - targetCol)
    // Adjacente se diferença é no máximo 1 em ambas direções (inclui diagonais)
    return rowDiff <= 1 && colDiff <= 1 && (rowDiff > 0 || colDiff > 0)
  }

  const allAdjacentRevealed = (row, col, grid) => {
    const adjacent = getAdjacentCells(row, col, grid.length)
    return adjacent.every(({ row: r, col: c }) => grid[r][c].revealed)
  }

  const isAdjacentToAnyRevealed = (row, col, grid) => {
    const adjacent = getAdjacentCells(row, col, grid.length)
    return adjacent.some(({ row: r, col: c }) => grid[r][c].revealed)
  }

  const handleSafariCellClick = async (row, col) => {
    if (!safariGridData || !safariActiveRun) return
    const runKey = `run-${safariActiveRun}`
    const currentTimer = safariTimers[runKey] !== undefined ? safariTimers[runKey] : 600
    const permissions = safariRunPermissions[runKey] || {}
    if (!permissions[currentUser?.username]) return

    const cell = safariGridData[row][col]

    // Bloquear tiles de lava (sempre)
    if (cell.specialTile === 'lava') return

    // Tile de corda: navegar para área anterior (sem validação de movimento)
    if (cell.specialTile === 'rope') {
      if (currentTimer <= 0) { alert('⏰ Tempo esgotado!'); return }
      const prevArea = CAVE_PREVIOUS_AREA[safariCurrentArea]
      if (!prevArea) return
      const newGrid = generateSafariGrid(prevArea)
      setSafariCurrentArea(prevArea)
      setSafariGridData(newGrid)
      setSafariGridClickCount(0)
      const resetPositions = Object.fromEntries(Object.entries(safariRunLastClicked).filter(([k]) => k !== runKey))
      setSafariRunLastClicked(resetPositions)
      syncGridToRun(newGrid, safariActiveRun)
      if (currentTimer > 0) updateSafariTimer(safariActiveRun, currentTimer - 60)
      const newRunAreas = { ...safariRunAreas, [runKey]: prevArea }
      setSafariRunAreas(newRunAreas)
      saveSafariToFirebase({ runAreas: newRunAreas, runPositions: resetPositions })
      const timestamp = new Date().toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' })
      addChatMessage({ username: 'Sistema', text: `${currentUser.username} (Run ${safariActiveRun}) subiu pela corda de volta para ${prevArea}!`, timestamp, isDiceRoll: false })
      return
    }

    // Tile de corda de neve: navegar para área anterior congelada (sem validação)
    if (cell.specialTile === 'ropeNeve') {
      if (currentTimer <= 0) { alert('⏰ Tempo esgotado!'); return }
      const prevArea = FROZEN_CAVE_PREVIOUS_AREA[safariCurrentArea]
      if (!prevArea) return
      const newGrid = generateSafariGrid(prevArea)
      setSafariCurrentArea(prevArea)
      setSafariGridData(newGrid)
      setSafariGridClickCount(0)
      const resetPositions = Object.fromEntries(Object.entries(safariRunLastClicked).filter(([k]) => k !== runKey))
      setSafariRunLastClicked(resetPositions)
      syncGridToRun(newGrid, safariActiveRun)
      if (currentTimer > 0) updateSafariTimer(safariActiveRun, currentTimer - 60)
      const newRunAreas = { ...safariRunAreas, [runKey]: prevArea }
      setSafariRunAreas(newRunAreas)
      saveSafariToFirebase({ runAreas: newRunAreas, runPositions: resetPositions })
      const timestamp = new Date().toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' })
      addChatMessage({ username: 'Sistema', text: `${currentUser.username} (Run ${safariActiveRun}) subiu pela corda de neve de volta para ${prevArea}!`, timestamp, isDiceRoll: false })
      return
    }

    // Tile de buraco: navegar para próxima caverna
    if (cell.specialTile === 'hole') {
      if (currentTimer <= 0) { alert('⏰ Tempo esgotado!'); return }
      const nextArea = CAVE_NEXT_AREA[safariCurrentArea]
      if (!nextArea) return
      // Verificar se o tile de buraco está no alcance
      const lastClicked = safariRunLastClicked[runKey]
      const revealedCells = safariGridData.flat().filter(c => c.revealed)
      const isFirstClick = revealedCells.length === 0
      if (!isFirstClick && lastClicked) {
        const dist = Math.max(Math.abs(row - lastClicked.row), Math.abs(col - lastClicked.col))
        if (dist > 1) { alert('⚠️ Você precisa estar adjacente ao buraco para entrar!'); return }
      } else if (isFirstClick) {
        if (!isEdgeCell(row, col, safariGridData.length)) { alert('⚠️ O primeiro clique deve ser na borda do grid!'); return }
      }
      const newGrid = generateSafariGrid(nextArea)
      setSafariCurrentArea(nextArea)
      setSafariGridData(newGrid)
      setSafariGridClickCount(0)
      const resetPositions = Object.fromEntries(Object.entries(safariRunLastClicked).filter(([k]) => k !== runKey))
      setSafariRunLastClicked(resetPositions)
      syncGridToRun(newGrid, safariActiveRun)
      if (currentTimer > 0) updateSafariTimer(safariActiveRun, currentTimer - 60)
      const newRunAreas = { ...safariRunAreas, [runKey]: nextArea }
      setSafariRunAreas(newRunAreas)
      saveSafariToFirebase({ runAreas: newRunAreas, runPositions: resetPositions })
      const timestamp = new Date().toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' })
      addChatMessage({ username: 'Sistema', text: `${currentUser.username} (Run ${safariActiveRun}) desceu pelo buraco para ${nextArea}!`, timestamp, isDiceRoll: false })
      return
    }

    // Tile de buraco de neve: navegar para próxima caverna congelada
    if (cell.specialTile === 'holeNeve') {
      if (currentTimer <= 0) { alert('⏰ Tempo esgotado!'); return }
      const nextArea = FROZEN_CAVE_NEXT_AREA[safariCurrentArea]
      if (!nextArea) return
      const lastClicked = safariRunLastClicked[runKey]
      const revealedCells = safariGridData.flat().filter(c => c.revealed)
      const isFirstClick = revealedCells.length === 0
      if (!isFirstClick && lastClicked) {
        const dist = Math.max(Math.abs(row - lastClicked.row), Math.abs(col - lastClicked.col))
        if (dist > 1) { alert('⚠️ Você precisa estar adjacente ao buraco de neve para entrar!'); return }
      } else if (isFirstClick) {
        if (!isEdgeCell(row, col, safariGridData.length)) { alert('⚠️ O primeiro clique deve ser na borda do grid!'); return }
      }
      const newGrid = generateSafariGrid(nextArea)
      setSafariCurrentArea(nextArea)
      setSafariGridData(newGrid)
      setSafariGridClickCount(0)
      const resetPositions = Object.fromEntries(Object.entries(safariRunLastClicked).filter(([k]) => k !== runKey))
      setSafariRunLastClicked(resetPositions)
      syncGridToRun(newGrid, safariActiveRun)
      if (currentTimer > 0) updateSafariTimer(safariActiveRun, currentTimer - 60)
      const newRunAreas = { ...safariRunAreas, [runKey]: nextArea }
      setSafariRunAreas(newRunAreas)
      saveSafariToFirebase({ runAreas: newRunAreas, runPositions: resetPositions })
      const timestamp = new Date().toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' })
      addChatMessage({ username: 'Sistema', text: `${currentUser.username} (Run ${safariActiveRun}) desceu pelo buraco de neve para ${nextArea}!`, timestamp, isDiceRoll: false })
      return
    }

    // Tile de pedra: bloquear
    if (cell.terrain === 'Pedra') return

    // Célula já revelada: ignorar (exceto Gelo em Cavernas Congeladas — o slide sempre pode ser disparado)
    const isGeloCave = cell.terrain === 'Gelo' && FROZEN_CAVE_AREAS.includes(safariCurrentArea)
    if (cell.revealed && !isGeloCave) return

    // Verificar timer para tiles normais
    if (currentTimer <= 0) {
      alert('⏰ Tempo esgotado! Você não pode mais interagir com o grid.')
      return
    }

    // Regras de movimento
    const revealedCells = safariGridData.flat().filter(c => c.revealed)
    const isFirstClick = revealedCells.length === 0
    const lastClicked = safariRunLastClicked[runKey]
    const isCave23 = safariCurrentArea === 'Caverna 2' || safariCurrentArea === 'Caverna 3'
    const isFrozenCave23 = safariCurrentArea === 'Caverna Congelada 2' || safariCurrentArea === 'Caverna Congelada 3'
    const playerSalto = (safariCurrentArea === 'Caverna 3') ? (safariSaltoValues[runKey] || 0) : 0
    const maxReach = playerSalto + 1

    if (isCave23) {
      if (isFirstClick) {
        const ropePos = findSpecialTile(safariGridData, 'rope')
        const isInitialArea = safariRunStartAreas[runKey] === safariCurrentArea
        if (isInitialArea && ropePos) {
          // Área inicial via dropdown: primeiro clique deve ser no tile mais longe da corda
          const farthest = getFarthestTileFromRope(safariGridData, ropePos)
          if (!farthest || row !== farthest.row || col !== farthest.col) {
            alert('⚠️ Você deve começar pelo tile mais distante da corda!')
            return
          }
        } else {
          // Entrada normal pela corda: deve ser adjacente ao tile de corda
          if (!ropePos || !isAdjacentToCell(row, col, ropePos.row, ropePos.col)) {
            alert('⚠️ Ao entrar na caverna, você deve clicar em um tile adjacente à corda!')
            return
          }
        }
      } else {
        const dist = lastClicked ? Math.max(Math.abs(row - lastClicked.row), Math.abs(col - lastClicked.col)) : Infinity
        const withinReach = dist <= maxReach
        const allLastAdjacentRevealed = lastClicked && allAdjacentRevealed(lastClicked.row, lastClicked.col, safariGridData)
        const isAdjacentToRevealed = isAdjacentToAnyRevealed(row, col, safariGridData)
        if (!withinReach) {
          if (!allLastAdjacentRevealed || !isAdjacentToRevealed) {
            alert(maxReach > 1 ? `⚠️ Você pode saltar sobre até ${playerSalto} tile(s), mas este tile está fora do alcance!` : '⚠️ Você só pode clicar em quadrados adjacentes ao último clicado!')
            return
          }
        }
      }
    } else if (isFrozenCave23) {
      // Cavernas Congeladas 2 e 3: primeiro clique adjacente à corda, depois movimento normal
      const ropePos = findSpecialTile(safariGridData, 'ropeNeve')
      if (isFirstClick) {
        if (!ropePos || !isAdjacentToCell(row, col, ropePos.row, ropePos.col)) {
          alert('⚠️ Ao entrar na caverna congelada, o primeiro clique deve ser adjacente à corda de neve!')
          return
        }
      } else {
        const isAdjacentToLast = lastClicked && isAdjacentToCell(row, col, lastClicked.row, lastClicked.col)
        const allLastAdjacentRevealed = lastClicked && allAdjacentRevealed(lastClicked.row, lastClicked.col, safariGridData)
        const isAdjacentToRevealed = isAdjacentToAnyRevealed(row, col, safariGridData)
        if (!isAdjacentToLast) {
          if (!allLastAdjacentRevealed || !isAdjacentToRevealed) {
            alert(!allLastAdjacentRevealed ? '⚠️ Você só pode clicar em quadrados adjacentes ao último clicado!' : '⚠️ Você só pode clicar em quadrados adjacentes aos já revelados!')
            return
          }
        }
      }
    } else {
      // Caverna 1, Caverna Congelada 1 e áreas normais
      if (isFirstClick) {
        if (!isEdgeCell(row, col, safariGridData.length)) {
          alert('⚠️ O primeiro clique deve ser em um dos quadrados da borda do grid!')
          return
        }
      } else {
        const isAdjacentToLast = lastClicked && isAdjacentToCell(row, col, lastClicked.row, lastClicked.col)
        const allLastAdjacentRevealed = lastClicked && allAdjacentRevealed(lastClicked.row, lastClicked.col, safariGridData)
        const isAdjacentToRevealed = isAdjacentToAnyRevealed(row, col, safariGridData)
        if (!isAdjacentToLast) {
          if (!allLastAdjacentRevealed || !isAdjacentToRevealed) {
            alert(!allLastAdjacentRevealed ? '⚠️ Você só pode clicar em quadrados adjacentes ao último clicado!' : '⚠️ Você só pode clicar em quadrados adjacentes aos já revelados!')
            return
          }
        }
      }
    }

    // Mecânica de deslizamento no gelo (Cavernas Congeladas 2 e 3)
    let finalRow = row, finalCol = col
    if (cell.terrain === 'Gelo' && FROZEN_CAVE_AREAS.includes(safariCurrentArea)) {
      const refPos = lastClicked || findSpecialTile(safariGridData, 'ropeNeve')
      if (refPos) {
        const dr = Math.sign(row - refPos.row)
        const dc = Math.sign(col - refPos.col)
        if (dr !== 0 || dc !== 0) {
          let sr = row, sc = col
          while (true) {
            const nr = sr + dr, nc = sc + dc
            if (nr < 0 || nr >= 8 || nc < 0 || nc >= 8) break
            const nCell = safariGridData[nr][nc]
            if (nCell.terrain === 'Pedra') break
            sr = nr; sc = nc
            if (nCell.terrain !== 'Gelo') break
          }
          finalRow = sr; finalCol = sc
        }
      }
    }

    // Se o deslizamento chegou a um tile especial, tratar como clique nele
    const slideDest = safariGridData[finalRow][finalCol]
    if (finalRow !== row || finalCol !== col) {
      if (slideDest.specialTile === 'holeNeve') {
        const nextArea = FROZEN_CAVE_NEXT_AREA[safariCurrentArea]
        if (nextArea && currentTimer > 0) {
          const newGrid = generateSafariGrid(nextArea)
          setSafariCurrentArea(nextArea)
          setSafariGridData(newGrid)
          setSafariGridClickCount(0)
          const resetPositions = Object.fromEntries(Object.entries(safariRunLastClicked).filter(([k]) => k !== runKey))
          setSafariRunLastClicked(resetPositions)
          syncGridToRun(newGrid, safariActiveRun)
          updateSafariTimer(safariActiveRun, currentTimer - 60)
          const newRunAreas = { ...safariRunAreas, [runKey]: nextArea }
          setSafariRunAreas(newRunAreas)
          saveSafariToFirebase({ runAreas: newRunAreas, runPositions: resetPositions })
          const timestamp = new Date().toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' })
          addChatMessage({ username: 'Sistema', text: `${currentUser.username} deslizou no gelo e caiu pelo buraco de neve para ${nextArea}!`, timestamp, isDiceRoll: false })
        }
        return
      }
      if (slideDest.specialTile === 'ropeNeve') {
        const prevArea = FROZEN_CAVE_PREVIOUS_AREA[safariCurrentArea]
        if (prevArea && currentTimer > 0) {
          const newGrid = generateSafariGrid(prevArea)
          setSafariCurrentArea(prevArea)
          setSafariGridData(newGrid)
          setSafariGridClickCount(0)
          const resetPositions = Object.fromEntries(Object.entries(safariRunLastClicked).filter(([k]) => k !== runKey))
          setSafariRunLastClicked(resetPositions)
          syncGridToRun(newGrid, safariActiveRun)
          updateSafariTimer(safariActiveRun, currentTimer - 60)
          const newRunAreas = { ...safariRunAreas, [runKey]: prevArea }
          setSafariRunAreas(newRunAreas)
          saveSafariToFirebase({ runAreas: newRunAreas, runPositions: resetPositions })
          const timestamp = new Date().toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' })
          addChatMessage({ username: 'Sistema', text: `${currentUser.username} deslizou no gelo e voltou para ${prevArea}!`, timestamp, isDiceRoll: false })
        }
        return
      }
    }

    // Se o destino final já foi revelado, apenas atualiza posição (sem re-revelar ou novo encontro)
    if (slideDest.revealed) {
      const newRunPositions = { ...safariRunLastClicked, [runKey]: { row: finalRow, col: finalCol } }
      setSafariRunLastClicked(newRunPositions)
      saveSafariToFirebase({ runPositions: newRunPositions })
      return
    }

    const newGrid = safariGridData.map((r, ri) =>
      (r || []).map((c, ci) => (ri === finalRow && ci === finalCol ? { ...c, revealed: true } : c))
    )
    const newRunPositions = { ...safariRunLastClicked, [runKey]: { row: finalRow, col: finalCol } }
    setSafariRunLastClicked(newRunPositions)
    setSafariGridData(newGrid)
    syncGridToRun(newGrid, safariActiveRun)
    if (currentTimer > 0) updateSafariTimer(safariActiveRun, currentTimer - 10)

    // Resetar salto após movimento (só Caverna 3)
    const newSaltoValues = (safariCurrentArea === 'Caverna 3' && playerSalto > 0)
      ? { ...safariSaltoValues, [runKey]: 0 }
      : safariSaltoValues
    if (safariCurrentArea === 'Caverna 3' && playerSalto > 0) {
      setSafariSaltoValues(newSaltoValues)
    }
    saveSafariToFirebase({ saltoValues: newSaltoValues, runPositions: newRunPositions })

    const timestamp = new Date().toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' })
    const terrenoLabel =
      slideDest.terrain === 'Cave' ? 'caverna' :
      slideDest.terrain === 'Grama' ? 'grama' :
      slideDest.terrain === 'Neve' ? 'neve' :
      slideDest.terrain === 'TerraNeivada' ? 'terra nevada' :
      slideDest.terrain === 'Gelo' ? 'gelo' : 'água'

    if (!slideDest.pokemon) {
      addChatMessage({ username: 'Sistema', text: `${currentUser.username} explorou a ${terrenoLabel}, mas não encontrou nenhum pokémon.`, timestamp, isDiceRoll: false })
      return
    }

    const pokemonData = await fetchSafariPokemonData(slideDest.pokemon)
    const imageUrl = pokemonData.imageUrl
    const types = pokemonData.types

    const gridWithImage = newGrid.map((r, ri) =>
      r.map((c, ci) => (ri === finalRow && ci === finalCol ? { ...c, imageUrl } : c))
    )
    setSafariGridData(gridWithImage)
    syncGridToRun(gridWithImage, safariActiveRun)

    const newEncounterPokemon = []
    for (let i = 0; i < slideDest.quantity; i++) {
      const npcPkm = generateSafariNpcPokemon(
        slideDest.pokemon,
        parseSafariLevel(slideDest.levelRange || slideDest.level.toString()),
        slideDest.isSkittish,
        imageUrl,
        types
      )
      newEncounterPokemon.push(npcPkm)
    }
    const newRunEncounters = { ...safariRunEncounters, [runKey]: newEncounterPokemon }
    setSafariRunEncounters(newRunEncounters)
    saveSafariToFirebase({ runEncounters: newRunEncounters, runPositions: newRunPositions, saltoValues: newSaltoValues })

    addChatMessage({ username: 'Sistema', text: `${currentUser.username} encontrou ${slideDest.quantity}x ${slideDest.pokemon} (Nv.${slideDest.level})${slideDest.isSkittish ? ' ⚠️ Arisco!' : ''} na ${terrenoLabel}!`, timestamp, isDiceRoll: false })
  }

  const handleSafariIsca = () => {
    if (!safariActiveRun || safariSelectedPokemon.size === 0) return
    const runKey = `run-${safariActiveRun}`
    const encounters = safariRunEncounters[runKey] || []
    const newEncounters = encounters.map(p => {
      if (!safariSelectedPokemon.has(p.id)) return p
      return { ...p, chanceFuga: Math.min(100, p.chanceFuga + 25), chanceCaptura: p.chanceCaptura - 25 }
    })
    const newRunEncounters = { ...safariRunEncounters, [runKey]: newEncounters }
    setSafariRunEncounters(newRunEncounters)
    saveSafariToFirebase({ runEncounters: newRunEncounters })

    const selectedNames = encounters.filter(p => safariSelectedPokemon.has(p.id)).map(p => p.species).join(', ')
    const timestamp = new Date().toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' })
    addChatMessage({ username: currentUser.username, text: `🍖 Jogou uma Isca em ${selectedNames}!`, timestamp, isDiceRoll: false, isAction: true })
  }

  const handleSafariSurpresa = () => {
    if (!safariActiveRun || safariSelectedPokemon.size === 0) return
    const runKey = `run-${safariActiveRun}`
    const encounters = safariRunEncounters[runKey] || []
    const newEncounters = encounters.map(p => {
      if (!safariSelectedPokemon.has(p.id)) return p
      return { ...p, chanceFuga: Math.max(0, p.chanceFuga - 25), chanceCaptura: p.chanceCaptura + 25 }
    })
    const newRunEncounters = { ...safariRunEncounters, [runKey]: newEncounters }
    setSafariRunEncounters(newRunEncounters)
    saveSafariToFirebase({ runEncounters: newRunEncounters })

    const selectedNames = encounters.filter(p => safariSelectedPokemon.has(p.id)).map(p => p.species).join(', ')
    const timestamp = new Date().toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' })
    addChatMessage({ username: currentUser.username, text: `💥 Ação Surpresa em ${selectedNames}!`, timestamp, isDiceRoll: false, isAction: true })
  }

  const handleSafariBall = () => {
    const safariballItem = keyItems.find(item => item.name === 'Safariball')
    if (!safariballItem || safariballItem.quantity < 1) {
      alert('Você não tem Safariballs!')
      return
    }
    if (safariballItem.quantity === 1) {
      setKeyItems(keyItems.filter(item => item.name !== 'Safariball'))
    } else {
      setKeyItems(keyItems.map(item =>
        item.name === 'Safariball' ? { ...item, quantity: item.quantity - 1 } : item
      ))
    }

    // Usar mod captura do primeiro pokemon selecionado
    const runKey = safariActiveRun ? `run-${safariActiveRun}` : null
    const encounters = runKey ? (safariRunEncounters[runKey] || []) : []
    const selectedPkm = encounters.find(p => safariSelectedPokemon.has(p.id))
    const modCaptura = selectedPkm ? selectedPkm.chanceCaptura : 0

    // Calcular modificadores de captura do treinador (Safari Mod Captura)
    let safariModifiersTotal = 0
    const safariModifierDetails = []
    const currentUserModifiers = userBattleModifiers[currentUser.username] || []

    for (const modIndex of safariActiveCaptureModifiers) {
      const modifier = currentUserModifiers[modIndex]
      if (!modifier || !modifier.aplicarCaptura) continue

      const processedMod = processCommandExpression(modifier.mod)
      if (processedMod) {
        safariModifiersTotal += processedMod.finalResult
        safariModifierDetails.push(`${modifier.nome}=${processedMod.finalResult}`)
      }
    }

    const roll = Math.floor(Math.random() * 100) + 1
    const finalRoll = roll - safariModifiersTotal // SUBTRAIR modificadores da rolagem

    const timestamp = new Date().toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' })
    const detailsParts = [`1d100 = ${roll}`]
    if (safariModifierDetails.length > 0) {
      detailsParts.push(`Mod. Safari: -${safariModifiersTotal} (${safariModifierDetails.join(', ')})`)
    }
    if (modCaptura !== 0) {
      detailsParts.push(`Mod. Pokémon: ${modCaptura >= 0 ? '+' : ''}${modCaptura}`)
    }
    detailsParts.push(`Total: ${finalRoll}`)

    addChatMessage({
      username: currentUser.username,
      text: `🎯 Lançou uma Safariball!`,
      timestamp,
      isDiceRoll: true,
      diceResult: finalRoll,
      diceDetails: detailsParts.join(' | ')
    })
  }

  const handleSafariFuga = () => {
    const hasCorreria = skills.ataque && skills.ataque.includes('Corrida')
    const runKey = safariActiveRun ? `run-${safariActiveRun}` : null
    const encounters = runKey ? (safariRunEncounters[runKey] || []) : []
    const numPokemon = encounters.length
    const dc = numPokemon + 8

    const roll = Math.floor(Math.random() * 20) + 1
    let total, diceDetails

    if (hasCorreria) {
      // Usar fórmula de perícia Corrida
      const count = skills.ataque.filter(s => s === 'Corrida').length
      const modAtaque = getModifier(ataqueEfetivo)

      let baseBonus, modifierMultiplier
      if (count === 1) {
        baseBonus = 2
        modifierMultiplier = 1
      } else {
        baseBonus = 4
        modifierMultiplier = 2
      }

      const modifierBonus = modifierMultiplier * modAtaque
      total = roll + baseBonus + modifierBonus
      diceDetails = `1d20 = ${roll} | ${baseBonus} + ${modifierMultiplier > 1 ? `${modifierMultiplier}x` : ''}Modificador(${modAtaque}) = ${modifierBonus} | Total: ${total} vs DC ${dc} (${numPokemon} pkm + 8) → ${total > dc ? '✅ Escapou!' : '❌ Falhou!'}`
    } else {
      // Fuga normal (sem perícia)
      const modVel = getModifier(velocidadeEfetiva)
      total = roll + modVel
      diceDetails = `1d20(${roll})+${modVel} = ${total} vs DC ${dc} (${numPokemon} pkm + 8) → ${total > dc ? '✅ Escapou!' : '❌ Falhou!'}`
    }

    const sucesso = total > dc

    const timestamp = new Date().toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' })
    addChatMessage({
      username: currentUser.username,
      text: `🏃 ${hasCorreria ? 'Correria' : 'Fuga'}!`,
      timestamp,
      isDiceRoll: true,
      diceResult: total,
      diceDetails: diceDetails
    })

    if (sucesso) {
      setSafariSubarea('Mapa Safari')
    }
  }

  // ==================== FUNÇÕES DE MANIPULAÇÃO DE TOKENS VTT ====================

  // Função para iniciar o arrasto de um token
  const handleTokenMouseDown = (tokenId, layer, event) => {
    event.preventDefault()
    event.stopPropagation()

    // Bloquear arrasto durante animação
    if (vttAnimatingToken && vttAnimatingToken.id === tokenId) return

    // Verificar permissões
    const tokens = layer === 'gm' ? vttGMTokens : layer === 'map' ? vttMapTokens : vttTokens
    const token = tokens.find(t => t.id === tokenId)

    if (!token) return

    // Mestre pode arrastar qualquer token
    // Jogadores só podem arrastar tokens que pertencem a eles ou que têm permissão
    const _dragPermKey = getTokenPermKey(token)
    const _hasDragPerm = vttTokenPermissions[_dragPermKey]?.includes(currentUser.username)
    if (currentUser.type !== 'mestre' && token.owner !== currentUser.username && !_hasDragPerm) {
      return
    }

    // Pegar posição do canvas
    const canvas = event.currentTarget.closest('[data-vtt-canvas]')
    const rect = canvas ? canvas.getBoundingClientRect() : { left: 0, top: 0 }

    // Calcular posição do mouse relativa ao canvas, considerando zoom e offset
    const z = vttViewportZoom, W = vttCanvasWidth, H = vttCanvasHeight
    const mouseX = (event.clientX - rect.left - vttViewportOffset.x - W / 2) / z + W / 2
    const mouseY = (event.clientY - rect.top - vttViewportOffset.y - H / 2) / z + H / 2

    // Offset é a diferença entre posição do mouse e posição do token
    const offsetX = mouseX - token.x
    const offsetY = mouseY - token.y

    // Calcular centro do token para a régua
    const tokenCenterX = token.x + token.size / 2
    const tokenCenterY = token.y + token.size / 2

    setSelectedToken(tokenId)
    setDraggingToken({ id: tokenId, layer, offsetX, offsetY, startX: tokenCenterX, startY: tokenCenterY })
    // Resetar régua ao iniciar novo arrasto
    vttRulerActiveRef.current = false
    setVttRulerActive(false)
    setVttRulerWaypoints([])
  }

  // Função para ativar a régua com tecla "Q" durante arrasto
  const activateRuler = () => {
    // Só ativa a régua se estiver arrastando um token
    if (!draggingToken) return

    // Pegar o token atual
    const tokens = draggingToken.layer === 'gm' ? vttGMTokens : draggingToken.layer === 'map' ? vttMapTokens : vttTokens
    const token = tokens.find(t => t.id === draggingToken.id)

    if (!token) return

    // Centro atual do token
    const tokenCenterX = token.x + token.size / 2
    const tokenCenterY = token.y + token.size / 2

    // Ativar régua a partir da posição atual do token (não do início do drag)
    const startPt = { x: tokenCenterX, y: tokenCenterY }
    vttRulerActiveRef.current = true
    vttRulerEndRef.current = startPt
    setVttRulerActive(true)
    setVttRulerStart(startPt)
    setVttRulerEnd(startPt)
    setVttRulerWaypoints([])
  }

  // Ativar modo de planejamento de rota com tecla W
  const activatePath = () => {
    if (!draggingToken) return
    const tokens = draggingToken.layer === 'gm' ? vttGMTokens : draggingToken.layer === 'map' ? vttMapTokens : vttTokens
    const token = tokens.find(t => t.id === draggingToken.id)
    if (!token) return
    const pathStart = { x: token.x, y: token.y }
    vttPathActiveRef.current = true
    vttPathCurrentRef.current = pathStart
    setVttPathActive(true)
    setVttPathStart(pathStart)
    setVttPathWaypoints([])
  }

  // Calcular caminho célula a célula entre uma série de pontos
  const computeCellPath = (points, cellW, cellH) => {
    const steps = []
    for (let i = 0; i < points.length - 1; i++) {
      const from = points[i]
      const to = points[i + 1]
      let col = Math.round(from.x / cellW)
      let row = Math.round(from.y / cellH)
      const toCol = Math.round(to.x / cellW)
      const toRow = Math.round(to.y / cellH)
      while (col !== toCol || row !== toRow) {
        const dCol = toCol - col
        const dRow = toRow - row
        col += dCol !== 0 ? Math.sign(dCol) : 0
        row += dRow !== 0 ? Math.sign(dRow) : 0
        steps.push({ x: col * cellW, y: row * cellH })
      }
    }
    return steps
  }

  // Iniciar animação célula a célula ao longo do caminho planejado
  const startPathAnimation = (tokenId, layer, allPoints, initialTokens) => {
    const cellW = vttCanvasWidth / vttGridColumns
    const cellH = vttCanvasHeight / vttGridRows
    const steps = computeCellPath(allPoints, cellW, cellH)
    if (steps.length === 0) {
      setVttAnimatingToken(null)
      return
    }
    let currentTokens = [...initialTokens]
    let stepIndex = 0
    const intervalId = setInterval(() => {
      if (stepIndex >= steps.length) {
        clearInterval(intervalId)
        setVttAnimatingToken(null)
        return
      }
      const pos = steps[stepIndex]
      currentTokens = currentTokens.map(t => t.id === tokenId ? { ...t, x: pos.x, y: pos.y } : t)
      if (layer === 'gm') {
        setVttGMTokens(currentTokens)
      } else if (layer === 'map') {
        setVttMapTokens(currentTokens)
        if (useFirebase) saveToFirebase('vtt/live/mapTokens', currentTokens)
      } else {
        setVttTokens(currentTokens)
        if (useFirebase) saveToFirebase('vtt/live/tokens', currentTokens)
      }
      stepIndex++
    }, 350)
  }

  // Função para mover o token durante o arrasto
  const handleTokenMouseMove = (event) => {
    if (!draggingToken) return

    event.preventDefault()

    const canvas = event.currentTarget
    const rect = canvas.getBoundingClientRect()

    // Calcular posição do mouse relativa ao canvas, considerando zoom e offset
    const z2 = vttViewportZoom, W2 = vttCanvasWidth, H2 = vttCanvasHeight
    let newX = (event.clientX - rect.left - vttViewportOffset.x - W2 / 2) / z2 + W2 / 2 - draggingToken.offsetX
    let newY = (event.clientY - rect.top - vttViewportOffset.y - H2 / 2) / z2 + H2 / 2 - draggingToken.offsetY

    // Aplicar snap to grid se ativo
    if (vttSnapToGrid) {
      const cellWidth = vttCanvasWidth / vttGridColumns
      const cellHeight = vttCanvasHeight / vttGridRows
      newX = Math.round(newX / cellWidth) * cellWidth
      newY = Math.round(newY / cellHeight) * cellHeight
    }

    // Atualizar posição do token
    if (draggingToken.layer === 'gm') {
      setVttGMTokens(prev => prev.map(t =>
        t.id === draggingToken.id ? { ...t, x: newX, y: newY } : t
      ))
    } else if (draggingToken.layer === 'map') {
      setVttMapTokens(prev => prev.map(t =>
        t.id === draggingToken.id ? { ...t, x: newX, y: newY } : t
      ))
    } else {
      setVttTokens(prev => prev.map(t =>
        t.id === draggingToken.id ? { ...t, x: newX, y: newY } : t
      ))
    }

    // Rastrear posição atual do token para o path (tecla W)
    if (vttPathActiveRef.current) {
      vttPathCurrentRef.current = { x: newX, y: newY }
    }

    // Atualizar posição final da régua se estiver ativa
    if (vttRulerActive) {
      // Pegar o tamanho do token para calcular o centro
      const tokens = draggingToken.layer === 'gm' ? vttGMTokens : draggingToken.layer === 'map' ? vttMapTokens : vttTokens
      const token = tokens.find(t => t.id === draggingToken.id)
      const tokenSize = token ? token.size : vttGridSize
      const newEnd = { x: newX + tokenSize / 2, y: newY + tokenSize / 2 }
      vttRulerEndRef.current = newEnd
      setVttRulerEnd(newEnd)
    }
  }

  // Função para finalizar o arrasto
  const handleTokenMouseUp = () => {
    // Modo de rota animada (tecla W): disparar animação célula a célula
    if (vttPathActiveRef.current && draggingToken) {
      const { id, layer } = draggingToken
      const finalPos = { x: vttPathCurrentRef.current.x, y: vttPathCurrentRef.current.y }
      const allPoints = [vttPathStart, ...vttPathWaypoints, finalPos]
      // Obter tokens atuais da camada correta
      const initialTokens = layer === 'gm' ? vttGMTokens : layer === 'map' ? vttMapTokens : vttTokens
      // Resetar o token para a posição inicial (âncora) antes de animar
      const resetFn = prev => prev.map(t => t.id === id ? { ...t, x: vttPathStart.x, y: vttPathStart.y } : t)
      if (layer === 'gm') setVttGMTokens(resetFn)
      else if (layer === 'map') setVttMapTokens(resetFn)
      else setVttTokens(resetFn)
      // Marcar token como animando e iniciar
      setVttAnimatingToken({ id, layer })
      // Usar setTimeout 0 para garantir que o reset de posição seja renderizado antes
      setTimeout(() => startPathAnimation(id, layer, allPoints, initialTokens.map(t => t.id === id ? { ...t, x: vttPathStart.x, y: vttPathStart.y } : t)), 0)
    }

    setDraggingToken(null)
    setVttDraggingMap(false)
    // Desativar régua
    vttRulerActiveRef.current = false
    setVttRulerActive(false)
    setVttRulerWaypoints([])
    // Desativar path
    vttPathActiveRef.current = false
    setVttPathActive(false)
    setVttPathWaypoints([])
  }

  // Abrir modal de edição de token
  const handleVttEditToken = (token, layer, e) => {
    e.stopPropagation()
    setVttEditingToken({ id: token.id, layer })
    setVttTokenEditUrl(token.image || '')
    setVttTokenEditOffsetY(token.offsetY || 0)
    setVttTokenEditScale(token.imageScale || 100)
  }

  // Salvar edição de token
  const handleVttSaveTokenEdit = () => {
    if (!vttEditingToken) return
    const { id, layer } = vttEditingToken
    const updater = prev => prev.map(t => t.id === id ? {
      ...t,
      image: vttTokenEditUrl,
      offsetY: vttTokenEditOffsetY,
      imageScale: vttTokenEditScale
    } : t)
    if (layer === 'gm') setVttGMTokens(updater)
    else if (layer === 'map') setVttMapTokens(updater)
    else setVttTokens(updater)
    setVttEditingToken(null)
  }

  // Remover token do canvas
  const handleVttRemoveToken = (tokenId, layer) => {
    if (layer === 'gm') setVttGMTokens(prev => prev.filter(t => t.id !== tokenId))
    else if (layer === 'map') setVttMapTokens(prev => prev.filter(t => t.id !== tokenId))
    else setVttTokens(prev => prev.filter(t => t.id !== tokenId))
    if (selectedToken === tokenId) {
      setSelectedToken(null)
      setVttSelectedPokemonToken(null)
      setVttContextMenuToken(null)
    }
    setVttEditingToken(null)
  }

  // Gerar token de treinador não-NPC e colocar na camada de jogadores
  const handleAddTrainerToken = (username, layer = 'tokens') => {
    const icon = TRAINER_ICONS[username] || null
    const cellWidth = vttCanvasWidth / vttGridColumns
    const cellHeight = vttCanvasHeight / vttGridRows
    const tokenSize = Math.min(cellWidth, cellHeight)
    const centerX = (vttCanvasWidth / 2) - (tokenSize / 2)
    const centerY = (vttCanvasHeight / 2) - (tokenSize / 2)
    const newToken = {
      id: `token-trainer-${username}-${Date.now()}`,
      name: username,
      x: centerX,
      y: centerY,
      size: tokenSize,
      rotation: 0,
      image: icon,
      owner: username,
      npcType: 'trainer',
      trainerUsername: username
    }
    if (layer === 'gm') setVttGMTokens(prev => [...prev, newToken])
    else if (layer === 'map') setVttMapTokens(prev => [...prev, newToken])
    else setVttTokens(prev => [...prev, newToken])
  }

  // Gerar token de Pokémon Prestativo/Parceiro e colocar na camada de jogadores
  const handleAddNpcPrestativoToken = (pokemon) => {
    const image = pokemon.imageUrl || null
    const cellWidth = vttCanvasWidth / vttGridColumns
    const cellHeight = vttCanvasHeight / vttGridRows
    const tokenSize = Math.min(cellWidth, cellHeight)
    const centerX = (vttCanvasWidth / 2) - (tokenSize / 2)
    const centerY = (vttCanvasHeight / 2) - (tokenSize / 2)
    const newToken = {
      id: `token-prestativo-${pokemon.id}-${Date.now()}`,
      name: pokemon.species || pokemon.name || 'Pokémon',
      x: centerX,
      y: centerY,
      size: tokenSize,
      rotation: 0,
      image,
      owner: currentUser.username,
      npcType: 'pokemon',
      npcId: pokemon.id
    }
    setVttTokens(prev => [...prev, newToken])
  }

  // Gerar token de Pokémon do time e colocar na camada de jogadores
  const handleAddPokemonToken = (pokemon, username) => {
    const imageKey = sanitizeFirebaseKey(pokemon.id)
    let image = getPokemonCurrentImage(pokemon.id) || pokemonImages[imageKey] || null
    if (!image) {
      image = SPECIES_CUSTOM_IMAGES[pokemon.species] || null
      if (!image) {
        const dexNum = fullPokedexData.find(p => p.nome === pokemon.species)?.dexNumber
        if (dexNum) image = `https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/${dexNum}.png`
      }
    }
    const cellWidth = vttCanvasWidth / vttGridColumns
    const cellHeight = vttCanvasHeight / vttGridRows
    const tokenSize = Math.min(cellWidth, cellHeight)
    const centerX = (vttCanvasWidth / 2) - (tokenSize / 2)
    const centerY = (vttCanvasHeight / 2) - (tokenSize / 2)
    const newToken = {
      id: `token-pokemon-${pokemon.id}-${Date.now()}`,
      name: pokemon.nickname || pokemon.species || 'Pokémon',
      x: centerX,
      y: centerY,
      size: tokenSize,
      rotation: 0,
      image,
      owner: username,
      npcType: 'pokemon',
      pokemonId: pokemon.id
    }
    setVttTokens(prev => [...prev, newToken])
  }

  // Selecionar token no canvas e, se for Pokémon, exibir no painel de golpes
  const handleVttTokenClick = (tokenId, layer) => {
    setSelectedToken(tokenId)
    setVttContextMenuToken(null)
    const tokens = layer === 'gm' ? vttGMTokens : layer === 'map' ? vttMapTokens : vttTokens
    const token = tokens.find(t => t.id === tokenId)
    if (token && token.pokemonId) {
      const pokemon = mainTeam.find(p => p.id === token.pokemonId)
      setVttSelectedPokemonToken(pokemon || null)
    } else if (token && token.npcId) {
      const pokemon = npcPokemon.find(p => p.id === token.npcId)
      if (pokemon) {
        const alfaBonus = npcAlfaStatus[pokemon.id] ? 8 : 0
        setVttSelectedPokemonToken({
          ...pokemon,
          golpes: pokemon.golpesAprendidos || [],
          totalAttributes: {
            ataque: (pokemon.attributes?.ataque || 0) + alfaBonus,
            ataqueEspecial: (pokemon.attributes?.ataqueEspecial || 0) + alfaBonus,
            defesa: (pokemon.attributes?.defesa || 0) + alfaBonus,
            defesaEspecial: (pokemon.attributes?.defesaEspecial || 0) + alfaBonus,
            velocidade: (pokemon.attributes?.velocidade || 0) + alfaBonus,
          },
          tipos: pokemon.types || [],
        })
      } else {
        setVttSelectedPokemonToken(null)
      }
    } else {
      setVttSelectedPokemonToken(null)
    }
  }

  // Desselecionar token ao pressionar Escape
  useEffect(() => {
    const handleKeyDown = (e) => {
      if (e.key === 'Escape' && selectedToken) {
        setSelectedToken(null)
        setVttSelectedPokemonToken(null)
        setVttContextMenuToken(null)
      }
    }
    window.addEventListener('keydown', handleKeyDown)
    return () => window.removeEventListener('keydown', handleKeyDown)
  }, [selectedToken])

  // ---- VTT Drawing Tools ----

  // Posição do mouse relativa ao canvas virtual (descontando pan e zoom)
  const getVttCanvasMousePos = (event) => {
    const canvas = vttCanvasRef.current
    if (!canvas) return { x: 0, y: 0 }
    const rect = canvas.getBoundingClientRect()
    const z = vttViewportZoom
    const W = vttCanvasWidth
    const H = vttCanvasHeight
    return {
      x: (event.clientX - rect.left - vttViewportOffset.x - W / 2) / z + W / 2,
      y: (event.clientY - rect.top - vttViewportOffset.y - H / 2) / z + H / 2
    }
  }

  // Publicar ferramenta ativa no Firebase para outros usuários verem
  const broadcastLiveTool = (data) => {
    if (!useFirebase || !currentUser) return
    const key = currentUser.username.replace(/[.#$[\]/]/g, '_')
    saveToFirebase(`vtt/liveTools/${key}`, data)
  }

  const clearLiveTool = () => {
    if (!useFirebase || !currentUser) return
    const key = currentUser.username.replace(/[.#$[\]/]/g, '_')
    set(ref(database, `vtt/liveTools/${key}`), null)
  }

  // Salvar stroke no Firebase
  const saveVttStroke = (stroke) => {
    if (!useFirebase) return
    const key = stroke.id.replace(/[.#$[\]/]/g, '_')
    saveToFirebase(`vtt/drawingStrokes/${key}`, stroke)
  }

  // Deletar stroke do Firebase
  const deleteVttStroke = (strokeId) => {
    if (!useFirebase) return
    const key = strokeId.replace(/[.#$[\]/]/g, '_')
    set(ref(database, `vtt/drawingStrokes/${key}`), null)
  }

  const deletePersistedRuler = (rulerId) => {
    setVttPersistedRulers(prev => prev.filter(r => r.id !== rulerId))
    if (useFirebase) {
      const key = rulerId.replace(/[.#$[\]/]/g, '_')
      set(ref(database, `vtt/persistedRulers/${key}`), null)
    }
  }

  // MouseDown no canvas quando uma ferramenta está ativa
  const distToSegment = (p, a, b) => {
    const dx = b.x - a.x, dy = b.y - a.y
    const lenSq = dx * dx + dy * dy
    if (lenSq === 0) return Math.hypot(p.x - a.x, p.y - a.y)
    const t = Math.max(0, Math.min(1, ((p.x - a.x) * dx + (p.y - a.y) * dy) / lenSq))
    return Math.hypot(p.x - (a.x + t * dx), p.y - (a.y + t * dy))
  }

  // Iniciar régua/coluna/explosão a partir do centro de um token
  const startToolFromToken = (token, event) => {
    if (!vttActiveTool || vttActiveTool === 'pincel') return false
    event.stopPropagation()
    const center = { x: token.x + token.size / 2, y: token.y + token.size / 2 }
    setVttToolStart(center)
    setVttToolEnd(center)
    setVttToolDrawing(true)
    setVttSelectedStroke(null)
    return true
  }

  // Lançar pokébola em token alvo (modo captura VTT)
  const handleVttCaptureToken = async (targetToken) => {
    if (!vttCaptureMode || !vttCapturePokeball) return
    const targetPkm = npcPokemon.find(p => p.id === targetToken.npcId)
    if (!targetPkm) return

    // Decrementar pokébola da mochila
    const updatedKeyItems = keyItems
      .map(item => item.name === vttCapturePokeball ? { ...item, quantity: item.quantity - 1 } : item)
      .filter(item => item.quantity === undefined || item.quantity > 0)
    setKeyItems(updatedKeyItems)

    // Calcular modificador da pokébola
    const pokeballMods = POKEBALL_MODIFIERS[vttCapturePokeball]
    const modifier = pokeballMods && pokeballMods !== 'custom' ? pokeballMods[0] : '0'
    const modifierValue = parseInt(modifier) || 0

    // Modificadores de batalha ativos com aplicarCaptura
    const currentUserMods = userBattleModifiers[currentUser.username] || []
    const currentUserActiveIdx = userActiveModifiers[currentUser.username] || []
    let battleModsTotal = 0
    const battleModDetails = []
    for (const idx of currentUserActiveIdx) {
      const bMod = currentUserMods[idx]
      if (!bMod || !bMod.aplicarCaptura) continue
      const num = parseInt(bMod.mod) || 0
      battleModsTotal += num
      battleModDetails.push(`${bMod.nome}=${num}`)
    }

    const hasCanhao = talentosSelected.some(t => t.nome === 'Canhão de Pokébolas')
    const d100Roll = Math.floor(Math.random() * 100) + 1
    let finalResult = d100Roll + modifierValue - battleModsTotal
    if (hasCanhao) finalResult -= 12

    await saveVTTCaptureRequest({
      trainerUsername: currentUser.username,
      pokeballName: vttCapturePokeball,
      modifier,
      modifierValue,
      battleModsTotal,
      battleModDetails,
      hasCanhao,
      d100Roll,
      finalResult,
      targetNpcId: targetToken.npcId,
      timestamp: Date.now()
    })

    setVttCaptureMode(false)
    setVttCapturePokeball(null)
  }

  const handleVttTokenImageSwitch = (tokenId, layer, direction) => {
    const setter = layer === 'gm' ? setVttGMTokens : layer === 'map' ? setVttMapTokens : setVttTokens
    setter(prev => prev.map(t => {
      if (t.id !== tokenId) return t
      const pkm = t.pokemonId ? mainTeam.find(p => p.id === t.pokemonId) : npcPokemon.find(p => p.id === t.npcId)
      if (!pkm) return t
      const allImages = getPokemonAllImages(pkm.id)
      if (allImages.length <= 1) return t
      const currentIdx = Math.max(0, allImages.indexOf(t.image))
      const nextIdx = direction === 'up'
        ? (currentIdx - 1 + allImages.length) % allImages.length
        : (currentIdx + 1) % allImages.length
      return { ...t, image: allImages[nextIdx] }
    }))
  }

  const handlePanelPokemonImageSwitch = (pokemonId, direction) => {
    const allImages = getPokemonAllImages(pokemonId)
    if (allImages.length <= 1) return
    const key = sanitizeFirebaseKey(pokemonId)
    const currentIdx = pokemonImageIndex[key] || 0
    const nextIdx = direction === 'up'
      ? (currentIdx - 1 + allImages.length) % allImages.length
      : (currentIdx + 1) % allImages.length
    setPokemonImageIndex(prev => ({ ...prev, [key]: nextIdx }))
    const newImage = allImages[nextIdx]
    const updateTokens = (tokens) => tokens.map(t => {
      if ((t.pokemonId || t.npcId) !== pokemonId) return t
      return { ...t, image: newImage }
    })
    setVttTokens(prev => updateTokens(prev))
    setVttGMTokens(prev => updateTokens(prev))
    setVttMapTokens(prev => updateTokens(prev))
  }

  const handleVttScanToken = (token) => {
    let species = null
    if (token.pokemonId) {
      const pkm = mainTeam.find(p => p.id === token.pokemonId)
      species = pkm?.species || null
    } else if (token.npcId) {
      const pkm = npcPokemon.find(p => p.id === token.npcId)
      species = pkm?.species || pkm?.name || null
    }
    // Fallback: usar o nome do token (útil para tokens NPC do mestre que o treinador não tem em estado local)
    if (!species) species = token.name || null
    if (!species) return
    const alreadyHas = pokedex.find(p => p.species === species)
    if (alreadyHas) {
      alert(`Você já possui os dados do pokémon ${species}`)
    } else {
      setPokedex(prev => [...prev, { species, isScanned: true, isCaptured: false, isExotic: false, exoticData: null }])
      alert(`Você escaneou o pokémon ${species}`)
    }
    setVttScanMode(false)
  }

  const handleVttToolMouseDown = (event) => {
    if (!vttActiveTool || event.button !== 0) return false
    event.preventDefault()
    const pos = getVttCanvasMousePos(event)
    if (vttActiveTool === 'pincel') {
      // Verificar se clicou em algum traço existente (seleção/arraste)
      const visibleStrokes = vttDrawingStrokes.filter(s => s.layer !== 'gm' || currentUser.type === 'mestre')
      for (let i = visibleStrokes.length - 1; i >= 0; i--) {
        const stroke = visibleStrokes[i]
        const hitRadius = Math.max((stroke.width || 3) / 2 + 6, 8) / vttViewportZoom
        let hit = false
        if (stroke.shape === 'circle') {
          const dist = Math.hypot(pos.x - stroke.cx, pos.y - stroke.cy)
          hit = dist <= stroke.r + hitRadius
        } else if (stroke.shape === 'rect') {
          const rx1 = Math.min(stroke.x1, stroke.x2), rx2 = Math.max(stroke.x1, stroke.x2)
          const ry1 = Math.min(stroke.y1, stroke.y2), ry2 = Math.max(stroke.y1, stroke.y2)
          hit = pos.x >= rx1 - hitRadius && pos.x <= rx2 + hitRadius && pos.y >= ry1 - hitRadius && pos.y <= ry2 + hitRadius
        } else {
          const pts = stroke.points || []
          for (let j = 0; j < pts.length - 1; j++) {
            if (distToSegment(pos, pts[j], pts[j + 1]) <= hitRadius) { hit = true; break }
          }
        }
        if (hit) {
          setVttSelectedStroke(stroke.id)
          const canMove = currentUser.type === 'mestre' || stroke.owner === currentUser.username
          if (canMove) setVttDraggingStroke({ id: stroke.id, startX: pos.x, startY: pos.y, curDx: 0, curDy: 0 })
          return true
        }
      }
      // Nenhum traço clicado — iniciar novo traço
      const layer = currentUser.type === 'mestre' ? vttCurrentLayer : 'players'
      const strokeId = `stroke-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`
      setVttCurrentStroke({ id: strokeId, owner: currentUser.username, layer, points: [pos], color: vttPincelColor, width: vttPincelWidth })
      setVttToolDrawing(true)
      setVttSelectedStroke(null)
    } else {
      setVttToolStart(pos)
      setVttToolEnd(pos)
      setVttToolDrawing(true)
      setVttSelectedStroke(null)
    }
    return true
  }

  // MouseMove no canvas quando uma ferramenta está ativa
  const handleVttToolMouseMove = (event) => {
    if (vttDraggingStroke) {
      const pos = getVttCanvasMousePos(event)
      setVttDraggingStroke(prev => prev ? { ...prev, curDx: pos.x - prev.startX, curDy: pos.y - prev.startY } : null)
      return true
    }
    if (!vttActiveTool || !vttToolDrawing) return false
    const pos = getVttCanvasMousePos(event)
    const layer = currentUser.type === 'mestre' ? vttCurrentLayer : 'players'
    if (vttActiveTool === 'pincel' && vttCurrentStroke) {
      const updated = { ...vttCurrentStroke, points: [...vttCurrentStroke.points, pos] }
      setVttCurrentStroke(updated)
      broadcastLiveTool({ type: 'pincel', layer, points: updated.points, color: vttPincelColor, width: vttPincelWidth })
    } else if (vttActiveTool !== 'pincel' && vttToolStart) {
      setVttToolEnd(pos)
      broadcastLiveTool({ type: vttActiveTool, layer, start: vttToolStart, end: pos, thickness: vttColunaThickness, radius: vttExplosaoRadius })
    }
    return true
  }

  // MouseUp no canvas quando uma ferramenta está ativa
  const handleVttToolMouseUp = () => {
    if (vttDraggingStroke) {
      const { id, curDx, curDy } = vttDraggingStroke
      if (curDx !== 0 || curDy !== 0) {
        setVttDrawingStrokes(prev => prev.map(s => {
          if (s.id !== id) return s
          let moved
          if (s.shape === 'circle') {
            moved = { ...s, cx: s.cx + curDx, cy: s.cy + curDy }
          } else if (s.shape === 'rect') {
            moved = { ...s, x1: s.x1 + curDx, y1: s.y1 + curDy, x2: s.x2 + curDx, y2: s.y2 + curDy }
          } else {
            moved = { ...s, points: s.points.map(p => ({ x: p.x + curDx, y: p.y + curDy })) }
          }
          saveVttStroke(moved)
          return moved
        }))
      }
      setVttDraggingStroke(null)
      return true
    }
    if (!vttActiveTool) return false
    if (vttActiveTool === 'pincel') {
      if (vttCurrentStroke && vttCurrentStroke.points.length > 1) {
        setVttDrawingStrokes(prev => [...prev, vttCurrentStroke])
        saveVttStroke(vttCurrentStroke)
      }
      setVttCurrentStroke(null)
      clearLiveTool()
    } else if ((vttActiveTool === 'pincel-circulo' || vttActiveTool === 'pincel-quadrado') && vttToolDrawing && vttToolStart && vttToolEnd) {
      const layer = currentUser.type === 'mestre' ? vttCurrentLayer : 'players'
      const strokeId = `stroke-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`
      let stroke = null
      if (vttActiveTool === 'pincel-circulo') {
        const r = Math.hypot(vttToolEnd.x - vttToolStart.x, vttToolEnd.y - vttToolStart.y)
        if (r > 3) stroke = { id: strokeId, owner: currentUser.username, layer, color: vttPincelColor, width: vttPincelWidth, shape: 'circle', cx: vttToolStart.x, cy: vttToolStart.y, r }
      } else {
        const dx = Math.abs(vttToolEnd.x - vttToolStart.x), dy = Math.abs(vttToolEnd.y - vttToolStart.y)
        if (dx > 3 || dy > 3) stroke = { id: strokeId, owner: currentUser.username, layer, color: vttPincelColor, width: vttPincelWidth, shape: 'rect', x1: vttToolStart.x, y1: vttToolStart.y, x2: vttToolEnd.x, y2: vttToolEnd.y }
      }
      if (stroke) { setVttDrawingStrokes(prev => [...prev, stroke]); saveVttStroke(stroke) }
      clearLiveTool()
    } else if (vttToolDrawing) {
      clearLiveTool()
    }
    setVttToolDrawing(false)
    setVttToolStart(null)
    setVttToolEnd(null)
    return true
  }

  // Funções para arrastar o mapa (quando na camada 'map') — zoom-aware
  const handleMapImageMouseDown = (event) => {
    if (vttCurrentLayer !== 'map' || currentUser.type !== 'mestre') return
    event.preventDefault()
    event.stopPropagation()
    setVttDraggingMap(true)
    setVttMapDragStart({
      clientX: event.clientX,
      clientY: event.clientY,
      origPos: { ...vttMapPosition }
    })
  }

  const handleMapImageMouseMove = (event) => {
    if (!vttDraggingMap) return
    event.preventDefault()
    const dx = (event.clientX - vttMapDragStart.clientX) / vttViewportZoom
    const dy = (event.clientY - vttMapDragStart.clientY) / vttViewportZoom
    setVttMapPosition({
      x: vttMapDragStart.origPos.x + dx,
      y: vttMapDragStart.origPos.y + dy
    })
  }

  const handleMapImageMouseUp = () => {
    setVttDraggingMap(false)
  }

  // Inicializar dimensões da imagem ao carregar (onLoad)
  const handleMapImageLoad = (e) => {
    if (!vttMapWidth && !vttMapHeight) {
      setVttMapWidth(Math.round(e.target.naturalWidth * vttMapScale / 100))
      setVttMapHeight(Math.round(e.target.naturalHeight * vttMapScale / 100))
    }
  }

  // Callback ref para adicionar listener de wheel com passive: false (bloqueia scroll da página)
  const setCanvasRef = useCallback((node) => {
    // Remover listener do nó anterior se existir
    if (vttCanvasRef.current && vttCanvasRef.current._wheelHandler) {
      vttCanvasRef.current.removeEventListener('wheel', vttCanvasRef.current._wheelHandler)
    }

    // Adicionar listener ao novo nó
    if (node) {
      const wheelHandler = (event) => {
        // Só fazer zoom se a tecla Ctrl estiver pressionada
        if (!event.ctrlKey) return

        event.preventDefault()
        event.stopPropagation()

        const zoomSpeed = 0.1
        const delta = event.deltaY > 0 ? -zoomSpeed : zoomSpeed

        setVttViewportZoom(prevZoom => {
          const newZoom = prevZoom + delta
          // Limitar zoom entre 0.25 (25%) e 4 (400%)
          return Math.min(Math.max(newZoom, 0.25), 4)
        })
      }
      node._wheelHandler = wheelHandler
      node.addEventListener('wheel', wheelHandler, { passive: false })
    }

    vttCanvasRef.current = node
  }, [])

  // Funções para pan (arrastar a visualização com botão direito do mouse)
  const handlePanStart = (event) => {
    // Iniciar pan com botão direito do mouse (button === 2)
    if (event.button === 2) {
      event.preventDefault()
      setVttIsPanning(true)
      setVttPanStart({ x: event.clientX - vttViewportOffset.x, y: event.clientY - vttViewportOffset.y })
    }
  }

  const handlePanMove = (event) => {
    if (vttIsPanning) {
      setVttViewportOffset({
        x: event.clientX - vttPanStart.x,
        y: event.clientY - vttPanStart.y
      })
    }
  }

  const handlePanEnd = () => {
    setVttIsPanning(false)
  }

  // Resetar zoom e pan
  const resetViewport = () => {
    setVttViewportZoom(1)
    setVttViewportOffset({ x: 0, y: 0 })
  }

  // Adicionar listeners globais para drag e tecla Q (régua com waypoints)
  useEffect(() => {
    if (draggingToken) {
      // Handler para teclas Q (régua) e W (rota animada)
      const handleKeyDown = (event) => {
        if (event.key === 'q' || event.key === 'Q') {
          if (!vttRulerActiveRef.current) {
            activateRuler()
          } else {
            setVttRulerWaypoints(prev => [...prev, { x: vttRulerEndRef.current.x, y: vttRulerEndRef.current.y }])
          }
        }
        if (event.key === 'w' || event.key === 'W') {
          if (!vttPathActiveRef.current) {
            activatePath()
          } else {
            // W seguintes adicionam waypoint na posição atual do token
            setVttPathWaypoints(prev => [...prev, { x: vttPathCurrentRef.current.x, y: vttPathCurrentRef.current.y }])
          }
        }
      }

      window.addEventListener('mouseup', handleTokenMouseUp)
      window.addEventListener('keydown', handleKeyDown)
      return () => {
        window.removeEventListener('mouseup', handleTokenMouseUp)
        window.removeEventListener('keydown', handleKeyDown)
      }
    }
  }, [draggingToken])

  // Deletar stroke selecionado com tecla Del/Delete
  useEffect(() => {
    const handleDelKey = (e) => {
      if ((e.key === 'Delete' || e.key === 'Del') && vttSelectedStroke) {
        const stroke = vttDrawingStrokes.find(s => s.id === vttSelectedStroke)
        if (!stroke) return
        if (currentUser.type !== 'mestre' && stroke.owner !== currentUser.username) return
        setVttDrawingStrokes(prev => prev.filter(s => s.id !== vttSelectedStroke))
        deleteVttStroke(vttSelectedStroke)
        setVttSelectedStroke(null)
      }
    }
    window.addEventListener('keydown', handleDelKey)
    return () => window.removeEventListener('keydown', handleDelKey)
  }, [vttSelectedStroke, vttDrawingStrokes, currentUser])

  // Tecla E — persistir régua ativa no mapa (clique direito para remover)
  const VTT_RULER_PALETTE = [
    '#ff4444','#ff7700','#ffcc00','#aaff00','#44ff44',
    '#00ff99','#00ffff','#00aaff','#4455ff','#8800ff',
    '#cc00ff','#ff00cc','#ff0077','#ff8888','#ffbb77',
    '#ffff44','#bbff44','#44ffbb','#44bbff','#bb77ff',
    '#ff77bb','#00ff66','#0077ff','#ff5500','#ff00ff',
    '#88ffff','#ff6688','#66ff88','#8888ff','#ffaa44',
  ]
  useEffect(() => {
    const handleEKey = (e) => {
      if (e.key !== 'e' && e.key !== 'E') return
      let rulerBase = null
      if (vttRulerActive && vttRulerStart && vttRulerEnd) {
        rulerBase = { id: `ruler-${Date.now()}`, type: 'regua-q', start: vttRulerStart, end: vttRulerEnd, waypoints: vttRulerWaypoints, owner: currentUser?.username || '' }
      } else if (vttToolDrawing && (vttActiveTool === 'regua' || vttActiveTool === 'regua-raio') && vttToolStart && vttToolEnd) {
        rulerBase = { id: `ruler-${Date.now()}`, type: vttActiveTool, start: vttToolStart, end: vttToolEnd, waypoints: [], owner: currentUser?.username || '' }
      }
      if (!rulerBase) return
      setVttPersistedRulers(prev => {
        const color = VTT_RULER_PALETTE[prev.length % VTT_RULER_PALETTE.length]
        const ruler = { ...rulerBase, color }
        if (useFirebase) {
          const key = ruler.id.replace(/[.#$[\]/]/g, '_')
          set(ref(database, `vtt/persistedRulers/${key}`), ruler)
        }
        return [...prev, ruler]
      })
    }
    window.addEventListener('keydown', handleEKey)
    return () => window.removeEventListener('keydown', handleEKey)
  }, [vttRulerActive, vttRulerStart, vttRulerEnd, vttRulerWaypoints, vttToolDrawing, vttActiveTool, vttToolStart, vttToolEnd, currentUser])

  // Scroll automático para última mensagem do chat (apenas dentro do container)
  useEffect(() => {
    if (chatContainerRef.current) {
      chatContainerRef.current.scrollTop = chatContainerRef.current.scrollHeight
    }
    if (batalhaChatContainerRef.current) {
      batalhaChatContainerRef.current.scrollTop = batalhaChatContainerRef.current.scrollHeight
    }
  }, [chatMessages])

  // Remove golpes Saraivada do slot quando a próxima mensagem do chat não for
  // uma rolagem daquele mesmo golpe canalizado pelo usuário atual
  useEffect(() => {
    if (Object.keys(pendingSaraivadaSlots).length === 0) return
    if (chatMessages.length === 0) return
    const lastMsg = chatMessages[chatMessages.length - 1]
    const slotsToRemove = []
    Object.entries(pendingSaraivadaSlots).forEach(([slotIdx, moveName]) => {
      const isRollOfThisMove = lastMsg.battleMove === moveName && lastMsg.username === currentUser?.username
      if (!isRollOfThisMove) slotsToRemove.push(parseInt(slotIdx))
    })
    if (slotsToRemove.length > 0) {
      setGolpesCanalizar(prev => {
        const u = [...prev]
        slotsToRemove.forEach(idx => { u[idx] = null })
        return u
      })
      setPendingSaraivadaSlots(prev => {
        const u = { ...prev }
        slotsToRemove.forEach(idx => { delete u[idx] })
        return u
      })
    }
  }, [chatMessages])

  useEffect(() => {
    if (gbChatContainerRef.current) {
      gbChatContainerRef.current.scrollTop = gbChatContainerRef.current.scrollHeight
    }
  }, [gbChatMessages])

  useEffect(() => {
    if (pokezapContainerRef.current) {
      pokezapContainerRef.current.scrollTop = pokezapContainerRef.current.scrollHeight
    }
  }, [pokezapMessages])

  // Sincronizar VTT em tempo real com Firebase
  useEffect(() => {
    if (!useFirebase) return

    const unsubscribe = subscribeToVTT((data) => {
      setVttLocations(data.locations || [])
      setCurrentVttLocation(data.currentLocation || null)
      setVttGridSize(data.gridSize || 50)
      setVttShowGrid(data.showGrid !== undefined ? data.showGrid : true)
      setVttSnapToGrid(data.snapToGrid !== undefined ? data.snapToGrid : true)
      setVttGridColumns(data.gridColumns || 16)
      setVttGridRows(data.gridRows || 16)
      // canvasWidth/Height agora são derivados (gridColumns × gridSize), não mais carregados do Firebase
    })

    return () => {
      if (unsubscribe) unsubscribe()
    }
  }, [])

  // Sincronizar tokens da camada de jogadores em tempo real (todos os clientes)
  useEffect(() => {
    if (!useFirebase) return
    const unsub = subscribeToFirebase('vtt/live/tokens', (data) => {
      const incoming = Array.isArray(data) ? data : (data && typeof data === 'object' ? Object.values(data) : [])
      setVttTokens(prev => JSON.stringify(prev) === JSON.stringify(incoming) ? prev : incoming)
    })
    return unsub
  }, [])

  // Salvar tokens da camada de jogadores em tempo real (todos os clientes, debounced)
  useEffect(() => {
    if (!useFirebase || !currentUser) return
    const timer = setTimeout(() => {
      saveToFirebase('vtt/live/tokens', vttTokens)
    }, 300)
    return () => clearTimeout(timer)
  }, [vttTokens])

  // Sincronizar tokens da camada de mapa em tempo real (todos os clientes)
  useEffect(() => {
    if (!useFirebase) return
    const unsub = subscribeToFirebase('vtt/live/mapTokens', (data) => {
      const incoming = Array.isArray(data) ? data : (data && typeof data === 'object' ? Object.values(data) : [])
      setVttMapTokens(prev => JSON.stringify(prev) === JSON.stringify(incoming) ? prev : incoming)
    })
    return unsub
  }, [])

  // Salvar tokens da camada de mapa em tempo real (apenas GM, debounced)
  useEffect(() => {
    if (!useFirebase || !currentUser || currentUser.type !== 'mestre') return
    const timer = setTimeout(() => {
      saveToFirebase('vtt/live/mapTokens', vttMapTokens)
    }, 300)
    return () => clearTimeout(timer)
  }, [vttMapTokens])

  // Sincronizar strokes de desenho em tempo real
  useEffect(() => {
    if (!useFirebase) return
    const unsub = subscribeToFirebase('vtt/drawingStrokes', (data) => {
      setVttDrawingStrokes(data ? Object.values(data).map(s => ({
        ...s,
        points: Array.isArray(s.points) ? s.points : Object.values(s.points || {})
      })) : [])
    })
    return unsub
  }, [])

  // Sincronizar ferramentas ao vivo de outros usuários em tempo real
  useEffect(() => {
    if (!useFirebase) return
    const unsub = subscribeToFirebase('vtt/liveTools', (data) => {
      setVttLiveTools(data || {})
    })
    return unsub
  }, [])

  // Sincronizar réguas persistidas em tempo real (todos os clientes)
  useEffect(() => {
    if (!useFirebase) return
    const unsub = subscribeToFirebase('vtt/persistedRulers', (data) => {
      setVttPersistedRulers(data ? Object.values(data) : [])
    })
    return unsub
  }, [])

  // Sincronizar permissões de tokens VTT em tempo real (todos os clientes)
  useEffect(() => {
    if (!useFirebase) return
    const unsub = subscribeToFirebase('vtt/live/tokenPermissions', (data) => {
      setVttTokenPermissions(data && typeof data === 'object' ? data : {})
    })
    return unsub
  }, [])

  // Salvar permissões de tokens VTT (apenas mestre, debounced)
  useEffect(() => {
    if (!useFirebase || !currentUser || currentUser.type !== 'mestre') return
    const timer = setTimeout(() => {
      saveToFirebase('vtt/live/tokenPermissions', vttTokenPermissions)
    }, 300)
    return () => clearTimeout(timer)
  }, [vttTokenPermissions])

  // Cursor VTT (captura e escaneamento) — único style element, sempre movido para o fim do <head>
  useEffect(() => {
    if (vttCaptureMode && vttCapturePokeball) {
      applyVttCursor(getPokeballImage(vttCapturePokeball))
    } else if (vttScanMode) {
      applyVttCursor(classes.includes('Engenheiro') ? '/coisasengenheiro/miniengedex.png' : '/pokedexpq.png')
    } else {
      applyVttCursor(null)
    }
    return () => applyVttCursor(null)
  }, [vttCaptureMode, vttCapturePokeball, vttScanMode, classes])

  // Esc cancela modos VTT (captura, escaneamento e ferramenta ativa)
  useEffect(() => {
    const handleEscVtt = (e) => {
      if (e.key !== 'Escape') return
      if (vttCaptureMode || vttScanMode) {
        setVttCaptureMode(false)
        setVttCapturePokeball(null)
        setVttScanMode(false)
      }
      if (vttActiveTool) {
        setVttActiveTool(null)
        setVttToolDrawing(false)
        setVttToolStart(null)
        setVttToolEnd(null)
        clearLiveTool()
      }
    }
    window.addEventListener('keydown', handleEscVtt)
    return () => window.removeEventListener('keydown', handleEscVtt)
  }, [vttCaptureMode, vttScanMode, vttActiveTool])

  // Listener de requisição de captura VTT (apenas mestre)
  const npcPokemonRef = useRef(npcPokemon)
  useEffect(() => { npcPokemonRef.current = npcPokemon }, [npcPokemon])
  const vttCaptureProcessedTsRef = useRef(0)
  useEffect(() => {
    if (!useFirebase || !currentUser || currentUser.type !== 'mestre') return
    // Ignorar eventos anteriores ao momento do login
    vttCaptureProcessedTsRef.current = Date.now()
    const unsub = subscribeToVTTCaptureRequest((data) => {
      if (!data || !data.timestamp) return
      if (data.timestamp <= vttCaptureProcessedTsRef.current) return
      vttCaptureProcessedTsRef.current = data.timestamp
      const targetPkm = npcPokemonRef.current.find(p => p.id === data.targetNpcId) || null
      setVttCaptureResultModal({ ...data, targetPokemon: targetPkm })
    })
    return () => unsub()
  }, [useFirebase, currentUser?.type])

  // Carregar tokens e mapa da localidade atual (apenas quando a localidade selecionada muda)
  useEffect(() => {
    if (!currentVttLocation || vttLocations.length === 0) {
      setVttMapImage(null)
      setVttTokens([])
      setVttGMTokens([])
      setVttMapTokens([])
      setVttMapPosition({ x: 0, y: 0 })
      return
    }

    const location = vttLocations.find(loc => loc.id === currentVttLocation)
    if (location) {
      // Marcar que estamos carregando para evitar que o effect de salvamento seja acionado
      isLoadingVttLocationRef.current = true

      setVttMapImage(location.mapUrl || null)
      setVttTokens(location.tokens || [])
      setVttGMTokens(location.gmTokens || [])
      setVttMapTokens(location.mapTokens || [])
      setVttMapPosition(location.mapPosition || { x: 0, y: 0 })
      setVttMapWidth(location.mapWidth || null)
      setVttMapHeight(location.mapHeight || null)

      // Resetar o flag após um pequeno delay para permitir que os states sejam atualizados
      setTimeout(() => {
        isLoadingVttLocationRef.current = false
      }, 100)
    }
  }, [currentVttLocation]) // IMPORTANTE: Apenas currentVttLocation, NÃO vttLocations

  // Salvar tokens e posição do mapa da localidade atual quando mudarem
  useEffect(() => {
    // Não salvar se estamos carregando dados de uma localidade
    if (isLoadingVttLocationRef.current) return
    if (!currentVttLocation || vttLocations.length === 0) return

    const currentLocation = vttLocations.find(loc => loc.id === currentVttLocation)
    if (!currentLocation) return

    // Verificar se realmente houve mudança em relação à localidade armazenada
    const currentTokensStr = JSON.stringify(currentLocation.tokens || [])
    const currentGmTokensStr = JSON.stringify(currentLocation.gmTokens || [])
    const currentMapTokensStr = JSON.stringify(currentLocation.mapTokens || [])
    const currentMapPosStr = JSON.stringify(currentLocation.mapPosition || { x: 0, y: 0 })
    const currentMapW = currentLocation.mapWidth || null
    const currentMapH = currentLocation.mapHeight || null

    const newTokensStr = JSON.stringify(vttTokens)
    const newGmTokensStr = JSON.stringify(vttGMTokens)
    const newMapTokensStr = JSON.stringify(vttMapTokens)
    const newMapPosStr = JSON.stringify(vttMapPosition)

    if (currentTokensStr === newTokensStr &&
        currentGmTokensStr === newGmTokensStr &&
        currentMapTokensStr === newMapTokensStr &&
        currentMapPosStr === newMapPosStr &&
        currentMapW === vttMapWidth &&
        currentMapH === vttMapHeight) {
      return // Nenhuma mudança real
    }

    const updatedLocations = vttLocations.map(loc => {
      if (loc.id === currentVttLocation) {
        return {
          ...loc,
          tokens: vttTokens,
          gmTokens: vttGMTokens,
          mapTokens: vttMapTokens,
          mapPosition: vttMapPosition,
          mapWidth: vttMapWidth,
          mapHeight: vttMapHeight
        }
      }
      return loc
    })

    setVttLocations(updatedLocations)
  }, [vttTokens, vttGMTokens, vttMapTokens, vttMapPosition, vttMapWidth, vttMapHeight])

  // Salvar dados do VTT no Firebase quando mudarem (com debounce)
  useEffect(() => {
    if (!useFirebase || !currentUser || currentUser.type !== 'mestre') return

    const timer = setTimeout(() => {
      const vttData = {
        locations: vttLocations,
        currentLocation: currentVttLocation,
        gridSize: vttGridSize,
        showGrid: vttShowGrid,
        snapToGrid: vttSnapToGrid,
        gridColumns: vttGridColumns,
        gridRows: vttGridRows,
        canvasWidth: vttCanvasWidth,
        canvasHeight: vttCanvasHeight
      }
      saveVTTData(vttData)
    }, 500)

    return () => clearTimeout(timer)
  }, [vttLocations, currentVttLocation, vttGridSize, vttShowGrid, vttSnapToGrid, vttGridColumns, vttGridRows, vttCanvasWidth, vttCanvasHeight])

  // Drag dos handles de redimensionamento da imagem do mapa
  useEffect(() => {
    if (!vttMapResizingHandle || !vttMapResizeStart) return
    const { clientX: sx, clientY: sy, origW, origH, origPos } = vttMapResizeStart
    const h = vttMapResizingHandle
    const onMove = (e) => {
      const dx = (e.clientX - sx) / vttViewportZoom
      const dy = (e.clientY - sy) / vttViewportZoom
      const wFactor = h.includes('e') ? 1 : h.includes('w') ? -1 : 0
      const hFactor = h.includes('s') ? 1 : h.includes('n') ? -1 : 0
      const newW = Math.max(50, origW + dx * wFactor)
      const newH = Math.max(50, origH + dy * hFactor)
      const dw = newW - origW
      const dh = newH - origH
      setVttMapWidth(newW)
      setVttMapHeight(newH)
      setVttMapPosition({ x: origPos.x + dw / 2 * wFactor, y: origPos.y + dh / 2 * hFactor })
    }
    const onUp = () => { setVttMapResizingHandle(null); setVttMapResizeStart(null) }
    window.addEventListener('mousemove', onMove)
    window.addEventListener('mouseup', onUp)
    return () => { window.removeEventListener('mousemove', onMove); window.removeEventListener('mouseup', onUp) }
  }, [vttMapResizingHandle, vttMapResizeStart, vttViewportZoom])

  // Canvas derivado: largura e altura = células × tamanho da célula (modelo Roll20)
  useEffect(() => {
    setVttCanvasWidth(vttGridColumns * vttGridSize)
    setVttCanvasHeight(vttGridRows * vttGridSize)
  }, [vttGridSize, vttGridColumns, vttGridRows])

