                  className="bg-gradient-to-r from-blue-600 to-cyan-600 text-white px-4 sm:px-3 sm:px-5 md:px-6 md:px-8 py-4 rounded-lg hover:from-blue-700 hover:to-cyan-700 font-semibold text-lg shadow-lg"
