                          battleEntry = battleTrainersList.find(t => t.npcId === token.npcId)
                          if (npcData) { baseDefesa = npcData.attributes?.defesa || 0; baseDefEsp = npcData.attributes?.defesaEspecial || 0; baseVel = npcData.attributes?.velocidade || 0; ataqueBase = npcData.attributes?.ataque || 0; trainerLevel = npcData.level || 1 }
                          const bid = battleEntry?.id || token.npcId
                          displayName = battleEntry && !revealedTrainers[bid] ? (battleEntry.nomeFalso || 'NPC') : (npcTrainers.find(t => t.id === token.npcId)?.name || token.name)
